window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]=window.__LIBQ["pham-nhan-tu-tien"]["q03"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]["artifacts"]={"updatedAt":"2026-07-05","count":170,"artifacts":[{"id":"tuyet-hong-lang","name":"Tuyết Hồng Lăng","cn":null,"category":"phi-hanh","categoryLabel":"Pháp khí phi hành","phamCap":"Thượng phẩm pháp khí phi hành","soHuu":["Thanh Hư môn (sở hữu môn phái)"],"trangThai":"đang dùng","blurb":"Pháp khí phi hành của Thanh Hư môn. Khi triển khai hóa thành hồng kiều (cầu vồng đỏ) khảm đầy điểm ngân quang chói mắt, đủ chở cả đoàn hàng chục người bay trên không. Khi thu lại biến thành một món như bằng gấm nhỏ gọn cầm tay.","detail":"Xuất hiện c175: Phù Vân Tử và đoàn Thanh Hư môn đi trên Tuyết Hồng Lăng từ trên cao hạ xuống điểm hẹn cấm địa. Trông như điểm sáng, bên dưới ngân quang chớp động; hạ xuống thành hồng kiều khảm ngân quang. Phù Vân Tử phất tay thu lại thành vật như bằng gấm. Đoàn Hoàng Phong cốc kinh ngạc; quản sự nhắc nhở giải thích.","nguon":["c0175"]},{"id":"thien-nguyet-than-chu","name":"Thiên Nguyệt thần chu","cn":"天月神舟","category":"phi-hanh","categoryLabel":"Pháp khí phi hành","phamCap":"Thượng phẩm pháp khí phi hành","soHuu":["Yểm Nguyệt tông (sở hữu môn phái)"],"trangThai":"dang-co","blurb":"Thuyền phi hành của Yểm Nguyệt tông, dùng chở cả đoàn đệ tử. Chạm trổ vàng bạc tả long họa phượng tinh xảo, phát hào quang trắng; khi triệt tiêu hào quang thu lại gọn. Nguy nga lộng lẫy hơn hẳn Tuyết Hồng Lăng Thanh Hư môn.","detail":"Xuất hiện c178: Nghê Thường tiên tử và đoàn Yểm Nguyệt tông xuất hiện từ xa trên Thiên Nguyệt thần chu. Thuyền chạm trổ vàng bạc tả long họa phượng, hào quang trắng bao phủ. Sau khi hạ cánh, Nghê Thường triệt tiêu hào quang thuyền.","nguon":["c0178","@c0211"],"aliases":["Thiên Nguyệt Thần Châu"]},{"id":"noi-dan-huyet-tuyen-giao","name":"Nội đan Huyết Tuyến Giao","cn":null,"category":"dan-duoc","categoryLabel":"Nội đan linh thú","phamCap":"Nội đan quý hiếm (trợ đột phá)","soHuu":["Phù Vân Tử (mang theo làm vật cược)"],"trangThai":"vật cược ván ba bên","blurb":"Nội đan của yêu thú Huyết Tuyến Giao. Hình cầu trắng được bao phủ bởi những sợi tơ màu máu li ti. Công dụng giúp linh thú đột phá lên tầng mới — loại nguyên liệu quý Lý Sư Tổ từng mai phục hơn 30 năm tại Bàn Long giang vẫn không bắt được. Phù Vân Tử dùng làm vật cược khích tướng thành công.","detail":"Xuất hiện c176: Phù Vân Tử tung ra nội đan Huyết Tuyến Giao — viên cầu trắng phủ tơ máu đỏ — làm mồi nhử. Lý Sư Tổ lộ vẻ mắt sáng lên vì từng theo đuổi vật này hơn 30 năm không thành. Đây là vật cược của Phù Vân Tử cho ván cược ba bên về kết quả Huyết Cấm Thí Luyện.","nguon":["c0176"]},{"id":"vo-hinh-cham","name":"Vô hình châm","cn":null,"category":"phu-bao","categoryLabel":"Phù bảo — ẩn hình công kích","phamCap":"Phù bảo thượng phẩm","soHuu":["Khung tiền bối (tự luyện, dùng làm vật cược)"],"trangThai":"vật cược ván ba bên","blurb":"Ba khối phù bảo do Khung tiền bối tự luyện lúc nhàn rỗi từ Ngũ kim chi tinh, kết hợp độc pháp Vô hình độn pháp. Ẩn hình đả thương người hoàn toàn trong vô hình — ngay cả Nguyên Anh kỳ tu sĩ cũng đau đầu ứng phó. Khung tiền bối dùng làm vật cược vì không có hậu nhân để truyền thừa.","detail":"Xuất hiện c176: Khung tiền bối đề cập 3 phù bảo Vô hình châm tự luyện lúc nhàn rỗi. Vật cược trong ván ba bên (c177): nếu Yểm Nguyệt tông thắng, Lý sư tổ và Phù Vân Tử mỗi người được 1 châm, 1 châm còn lại Khung giữ. Chất liệu: Ngũ kim chi tinh; vận dụng pháp Vô hình độn pháp đặc trưng của Khung.","nguon":["c0176","c0177"]},{"id":"ngan-giap-giac-mang","name":"Ngân Giáp Giác Mãng","cn":null,"category":"linh-thu","categoryLabel":"Linh thú phi hành","phamCap":"Trúc Cơ trung kỳ (linh thú)","soHuu":["Lý Sư Tổ (linh thú)"],"trangThai":"đang dùng","blurb":"Linh thú rắn lớn của Lý Sư Tổ, thân dài hơn 20 trượng, vảy bạc sáng loáng, có sừng đen. Tu vi Trúc Cơ trung kỳ. Dùng làm phương tiện phi hành chở cả đoàn Hoàng Phong cốc từ tông môn tới điểm hẹn cấm địa — 2 ngày bay.","detail":"Xuất hiện c174: Lý Sư Tổ cưỡi Ngân Giáp Giác Mãng dẫn đoàn tới điểm hẹn Kiến Châu trong 2 ngày. Xác nhận c176: Phù Vân Tử đề cập nội đan Huyết Tuyến Giao có thể giúp linh thú đột phá; Lý sư tổ mắt sáng lên — hàm ý Ngân Giáp Giác Mãng là đối tượng muốn giúp đột phá.","nguon":["c0174","c0176"]},{"id":"tui-to-vang","name":"Túi trữ vật bằng tơ vàng","cn":null,"category":"tru-vat","categoryLabel":"Túi trữ vật đặc chế","phamCap":"Thượng phẩm (đặc chế)","soHuu":["Lý Sư Tổ (đặc chế, dùng một lần)"],"trangThai":"đã dùng @c174","blurb":"Túi trữ vật bằng tơ vàng đặc chế, không thể nhận thần thức hay linh lực thẩm tra từ bên ngoài. Mục đích: chứa thượng phẩm pháp khí để bốc thăm công bằng. Từng đệ tử chỉ được thò tay vào bốc, không thể biết trước hay can thiệp bằng thần thức.","detail":"Xuất hiện c174: Lý Sư Tổ rút túi tơ vàng ra bảo đệ tử bốc thăm pháp khí phân công cho chuyến thí luyện. Túi đặc chế ngăn thần thức và linh lực — đảm bảo công bằng tuyệt đối. Mỗi đệ tử thò tay vào bốc một pháp khí thượng phẩm.","nguon":["c0174"]},{"id":"gioi-thuoc","name":"Giới thước","cn":null,"category":"phap-bao-ban-menh","categoryLabel":"Pháp bảo bản mệnh","phamCap":"Pháp bảo bản mệnh Kết Đan kỳ","soHuu":["Lý Sư Tổ"],"trangThai":"đang dùng","blurb":"Pháp bảo bản mệnh của Lý Sư Tổ — hình dạng giới thước (thước kẻ dài), hào quang màu bạc trắng, như có linh tính. Dùng trong trận phá cấm chế Phong nhận đại trận trước cấm địa: đập nát vô số phong nhận liên tục, mở thông đường cho đệ tử vào cấm địa.","detail":"Xuất hiện c179: Lý Sư Tổ xuất pháp bảo bản mệnh cùng 6 tổ sư khác phá Phong nhận đại trận 3-4 canh giờ. Giới thước hào quang bạc như có linh tính, liên tục đập nát phong nhận cho tới khi đại trận phá thông.","nguon":["c0179"]},{"id":"thanh-quan-kiem","name":"Thanh Quân kiếm","cn":null,"category":"phi-kiem","categoryLabel":"Phi kiếm pháp bảo","phamCap":"Thượng phẩm pháp bảo phi kiếm","soHuu":["Phù Vân Tử"],"trangThai":"đang dùng","blurb":"Phi kiếm pháp bảo của Phù Vân Tử, Thanh Hư môn. Đã được luyện nhập khối thiết tinh của Lý Sư Tổ (kết quả ván cược cũ), làm uy lực tăng mạnh đáng kể. Trong trận phá cấm địa, Phù Vân Tử phun ra thanh quang hóa phi kiếm huyễn thành giao long dài vài chục trượng.","detail":"Đề cập c175: Lý sư tổ và Phù Vân Tử bàn về ván cược cũ — Lý sư tổ phải luyện nhập thiết tinh vào Thanh Quân kiếm của Phù Vân Tử, làm uy lực kiếm tăng mạnh. Dùng c179: Phù Vân Tử vỗ ót há miệng phun thanh quang hóa phi kiếm, huyễn thành giao long vài chục trượng tấn công Phong nhận đại trận.","nguon":["c0175","c0179"]},{"id":"han-yen-thao","name":"Hàn yên thảo","cn":null,"category":"linh-thao","categoryLabel":"Kỳ thảo cấm địa","phamCap":"Kỳ thảo quý hiếm (không phải Trúc Cơ đan chủ dược)","soHuu":["mọc tự nhiên tại Ô Long đàm (cấm địa)"],"trangThai":"mọc trong cấm địa","blurb":"Kỳ thảo hiếm trong cấm địa Huyết Cấm, mọc tự nhiên tại bờ Ô Long đàm. Năm lá trắng tuyền tỏa bạch khí, thân nhỏ. Mỗi khoảng hơn mười mấy năm mới xuất hiện một lần ở bờ đầm. Được trọng thưởng nếu mang về — nhưng không phải chủ dược Trúc Cơ đan.","detail":"Xuất hiện c180: Hàn Lập phát hiện Hàn yên thảo trên bờ Ô Long đàm trong cấm địa. Mô tả: 5 lá trắng tuyền tỏa bạch khí. Được nghe nhắc là loại kỳ thảo mỗi hơn mười mấy năm mới xuất hiện ở bờ đầm, giá trị cao, mang về được trọng thưởng. Hàn Lập nén hưng phấn, thầm ghi địa điểm.","nguon":["c0180"]},{"id":"khu-thu-phan","name":"Khu thú phấn","cn":null,"category":"doc-duoc","categoryLabel":"Bột độc — khống chế yêu thú","phamCap":"Đặc sản Linh Thú Sơn","soHuu":["Vu sư huynh và đồng bọn Linh Thú Sơn"],"trangThai":"đã dùng @c180","blurb":"Bột đặc chế của Linh Thú Sơn dùng để khống chế tạm thời yêu thú. Rải xuống nước hoặc môi trường sống của yêu thú, tạm thời vô hiệu hóa ý chí kháng cự. Vu sư huynh dùng Khu thú phấn khống chế đám Hàn băng thiềm tại Ô Long đàm trong kế giết người.","detail":"Xuất hiện c180: Vu sư huynh rải Khu thú phấn xuống Ô Long đàm, khống chế tạm thời đàn Hàn băng thiềm trong đó. Sau đó phối hợp Băng trùy thuật tấn công từ trước, Hàn băng thiềm tấn công từ sau lưng đệ tử Thiên Khuyết Bảo — giết hắn.","nguon":["c0180"]},{"id":"ti-tuyen","name":"Ti tuyến","cn":"","aliases":["Sợi tơ trong suốt"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":[],"trangThai":"khac","blurb":"Sợi tơ kỳ quái trong suốt lấp lóe, dùng làm vũ khí đánh lén cắt đứt cổ đối phương.","detail":"Sợi ti tuyến trong suốt kỳ quái, lấp lóe dưới nắng, quấn trên ngón vô danh của một sư huynh Hoàng Phong cốc. Đây là pháp khí sát thương âm hiểm: vị sư huynh dùng nó đánh lén cắt đứt cổ đệ tử Cự kiếm môn có thực lực cao hơn, dù cuối cùng cả hai đồng quy vu tận.","nguon":["@c0181"]},{"id":"buom-buom-canh-gioi-linh-thu-son","name":"Bươm bướm cảnh giới Linh thú sơn","cn":"","aliases":["Bươm bướm nhiều màu"],"category":"linh-khi","categoryLabel":"Linh trùng khu sử","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Côn trùng biến màu ngụy trang, được thả thành lưới cảnh giới sống trăm trượng.","detail":"Loài bươm bướm nhiều màu có thể biến ảo màu sắc theo cảnh vật, được đệ tử Linh thú sơn bố trí dày đặc trong phạm vi trăm trượng làm lưới cảnh giới sống, phát hiện ngay khi có người tiếp cận. Chúng trời sinh sợ lạnh, gặp nhiệt độ thấp là đông cứng chết, nên không thả được quanh vùng nước lạnh dị chất như Ô long đàm.","nguon":["@c0181"]},{"id":"tui-da-do","name":"Túi da màu đỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo chứa đồ","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Túi da màu đỏ hai đệ tử Linh thú sơn dùng thu chứa chiến lợi phẩm.","detail":"Túi da màu đỏ được hai đệ tử Linh thú sơn dùng để thu Hàn băng thiềm sau khi giết đệ tử Thiên khuyết bảo và cướp chiến lợi phẩm tại hiện trường.","nguon":["@c0181"]},{"id":"hoang-lat-hoan","name":"Hoàng lật hoàn","cn":"","category":"dan-duoc","categoryLabel":"Thức ăn linh cầm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"khac","blurb":"Món ăn Vân sí điểu yêu thích, thứ Hàn Lập dùng dụ chim quay về.","detail":"Hoàng lật hoàn là món Vân sí điểu ưa thích. Thời gian đầu sau khi được thả tự do trong Thái Nhạc sơn mạch, chim thường quay về tìm Hàn Lập để ăn Hoàng lật hoàn, nhưng về sau thưa dần rồi hoàn toàn hoang dã, một đi không trở lại.","nguon":["@c0181"]},{"id":"cu-kiem-cu-kiem-mon","name":"Cự kiếm (Cự kiếm môn)","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":[],"trangThai":"khac","blurb":"Thanh cự kiếm của đệ tử Cự kiếm môn, đâm xuyên đầu sư huynh Hoàng Phong cốc ghim xuống đất.","detail":"Thanh cự kiếm của đệ tử Cự kiếm môn áo đen. Trước khi chết vì bị ti tuyến cắt đứt cổ, người này còn thừa lực đâm một kiếm xuyên qua đầu sư huynh Hoàng Phong cốc, ghim thi thể xuống đất, tạo thành trận tử chiến không người thắng.","nguon":["@c0181"]},{"id":"mac-don-phu","name":"Mộc độn phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Trung cấp bậc thấp","soHuu":["Thiếu nữ áo trắng (Yểm Nguyệt tông)"],"trangThai":"da-dung","aliases":["Mộc độn thuật phù"],"blurb":"Phù lục Mộc độn thuật trung cấp bậc thấp, hiếm thấy trong tu tiên giới, là lợi khí chạy trốn tốt nhất lúc sinh tử.","detail":"Phù lục trung cấp bậc thấp cực hiếm, người thường coi là bảo vật gia truyền dùng lúc sinh tử. Thiếu nữ áo trắng Yểm Nguyệt tông dùng nó, cả người chìm trong màn lục quang chói mắt rồi biến mất khỏi cấm địa.","nguon":["@c0182"]},{"id":"thuy-trao-phong-ngu","name":"Thủy tráo phòng ngự","cn":"","category":"phap-bao","categoryLabel":"Pháp thuật phòng ngự","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp thuật phòng ngự dạng màn nước Hàn Lập tung ra đầu tiên khi bị phục kích để tự vệ.","detail":"Khi bị hai tu sĩ chặn tại Nhất tuyến thiên, Hàn Lập lập tức tung thủy tráo phòng ngự làm lớp bảo hộ trước khi bày các pháp bảo khác.","nguon":["@c0183"]},{"id":"phi-thien-thuan","name":"Phi thiên thuẫn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phòng ngự","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Khiên bay Hàn Lập phóng ra làm lớp phòng ngự khi giao tranh.","detail":"Pháp bảo phòng ngự dạng khiên bay, được Hàn Lập triển khai trong trận một địch hai tại Nhất tuyến thiên.","nguon":["@c0183"]},{"id":"kim-phu-tu-mau-nhan","name":"Kim phù tử mẫu nhận","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp khí Hàn Lập cầm sẵn trong tay khi đối trận với hai kẻ phục kích.","detail":"Được Hàn Lập cầm sẵn cùng phù Thổ lao thuật khi bày thế phòng ngự tại Nhất tuyến thiên.","nguon":["@c0183"]},{"id":"tho-lao-thuat","name":"Thổ lao thuật","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Phù lục sơ cấp bậc cao","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Phù lục sơ cấp bậc cao; khi ném ra biến thành đạo hoàng quang bao lấy phòng ngự đối phương thành lớp vỏ vàng, giam giữ khiến không nhúc nhích được.","detail":"Hàn Lập bất ngờ ném Thổ lao thuật về phía gã râu quai nón; phù biến thành hoàng quang bao chặt lớp phòng ngự của gã, hình thành lớp vỏ vàng lớn hơn giam hắn không thể đi tới chút nào.","nguon":["@c0183"]},{"id":"dung-linh-phu","name":"Dung linh phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Phù lục bậc cao","soHuu":["Nghiêm (đệ tử Thiên khuyết bảo)","Gã râu quai nón (tu sĩ Linh thú sơn)"],"trangThai":"da-dung","blurb":"Phù lục bậc cao dùng đồng thời bởi hai người một khắc trước khi vào cấm địa, tạm liên kết linh khí hai người để cấm chế truyền tới cùng một chỗ; tỉ lệ thành công năm-năm, giá cực đắt.","detail":"Công cụ giúp gã râu quai nón và đệ tử Thiên khuyết bảo tụ tập cùng điểm trong cấm địa để phục kích Hàn Lập. Hai người dùng đồng thời phù này ngay trước khi vào cấm địa; linh khí tạm thời liên kết nên cấm chế truyền hai người tới cùng chỗ, dù tỉ lệ thành công chỉ năm-năm và giá cực đắt.","nguon":["@c0183"]},{"id":"phu-luc-hao-quang-xanh-biec","name":"Phù lục phòng hộ hào quang xanh biếc","cn":"","category":"phap-bao","categoryLabel":"Phù lục phòng ngự","phamCap":"Không rõ","soHuu":["Gã râu quai nón (tu sĩ Linh thú sơn)"],"trangThai":"da-dung","blurb":"Phù lục phòng ngự gã râu quai nón dùng giữa đường tiến tới, dựng màn hào quang xanh biếc gia tăng phòng hộ.","detail":"Trên đường tiến tới hạ sát Hàn Lập, gã râu quai nón dùng phù lục này dựng màn hào quang xanh biếc bao quanh mình để tăng phòng hộ.","nguon":["@c0183"]},{"id":"tui-mau-xanh-ga-rau-quai-non","name":"Túi màu xanh","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Gã râu quai nón (tu sĩ Linh thú sơn)"],"trangThai":"dang-co","blurb":"Túi màu xanh gã râu quai nón hạ xuống trước khi ra tay đối phó Hàn Lập.","detail":"Trước khi tiến tới giao chiến, gã râu quai nón hạ túi màu xanh xuống rồi cười nanh ác tiến tới.","nguon":["@c0183"]},{"id":"kim-quang-chuyen","name":"Kim quang chuyên","aliases":["Kim chuyên"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phù bảo hình chữ nhật kim quang sáng rực, phát linh khí tận trời; khi khởi động hút ba phần pháp lực người dùng rồi phóng ra đè chết địch.","detail":"Vật thể hình chữ nhật kim quang sáng rực, mua từ Vạn bảo các. Khi khởi động, phù bảo liều mạng hút pháp lực trong cơ thể người dùng cuồn cuộn không dứt (bị ví “quỷ hút máu chết người”), sau khi hút ba phần mới dừng và trả quyền khống chế. Phóng ra đón gió lớn lên bằng gian phòng rồi như ngọn núi nhỏ vỗ thẳng xuống, đè thủng hố sâu cả trượng rộng vài chục trượng, phá nát mọi phòng hộ và thổ lao; đã đè chết tên râu quai nón tầng mười ba thành đám bùn.","nguon":["@c0184"]},{"id":"vong-bao-ho-moc-thuoc-tinh","name":"Vòng bảo hộ mộc thuộc tính","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tên râu quai nón (Linh thú sơn)"],"trangThai":"hong","blurb":"Pháp bảo phòng hộ mộc thuộc tính trên người tên râu quai nón, lực phòng hộ kinh người.","detail":"Vòng bảo hộ mộc thuộc tính khiến tên râu quai nón khinh thường màn tấn công của Hàn Lập, nhưng cuối cùng bị Kim quang chuyên phá nát cùng chủ nhân.","nguon":["@c0184"]},{"id":"doi-thiet-bong-den","name":"Đôi thiết bổng đen","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Tên râu quai nón (Linh thú sơn)"],"blurb":"Đôi thiết bổng màu đen tên râu quai nón dùng để công phá màn hào quang thổ lao.","detail":"Tên râu quai nón dùng đôi thiết bổng đen cùng linh thú công phá màn hào quang Thổ lao thuật vây khốn hắn.","nguon":["@c0184"]},{"id":"cu-kiem-mau-bac","name":"Cự kiếm màu bạc","aliases":["Cự kiếm bạc"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Đại hán cự kiếm bạc"],"trangThai":"dang-co","blurb":"Cự kiếm màu bạc của đại hán chân trần, chém thượng phẩm pháp khí và vòng bảo hộ như cắt giấy, chém đứt người thành hai nửa.","detail":"Là món pháp khí duy nhất đại hán chân trần sử dụng. Uy lực áp đảo: chém thượng phẩm pháp khí và vòng bảo hộ như cắt giấy, chém Tiêu Nhị thành hai đoạn. Đại hán không lấy pháp bảo nào khác vì cho rằng chúng làm hắn phân tâm, bất lợi cho tu hành.","nguon":["@c0185"]},{"id":"phi-dao-mau-do-han-thien-nhai","name":"Phi đao màu đỏ","aliases":["Phi đao hồng quang"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Thiên Nhai"],"trangThai":"dang-co","blurb":"Hai thanh phi đao hồng quang của Hàn Thiên Nhai, dùng giết nữ đệ tử Yểm nguyệt tông.","detail":"Hai thanh phi đao màu đỏ tỏa hồng quang, tốc độ nhanh như sấm sét; Hàn Thiên Nhai dùng chúng bất ngờ giết chết nữ đệ tử Yểm nguyệt tông sau khi giả vờ tha.","nguon":["@c0185"]},{"id":"phap-khi-nhu-manh-lua","name":"Pháp khí như mảnh lụa","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Nữ đệ tử Yểm nguyệt tông"],"trangThai":"mat","blurb":"Pháp khí phòng ngự như mảnh lụa của nữ đệ tử Yểm nguyệt tông, dùng ngăn hai phi đao hồng quang nhưng dần thất thế.","detail":"Pháp khí phòng ngự có hình như mảnh lụa; nữ đệ tử Yểm nguyệt tông dùng chống hai phi đao hồng quang của Hàn Thiên Nhai nhưng sắp không chống nổi, sau khi nàng thu pháp khí để đổi lấy mạng thì bị giết.","nguon":["@c0185"]},{"id":"guong-nho-che-ngu-phap-khi","name":"Gương nhỏ chế ngự pháp khí (nữ áo trắng)","category":"phap-bao","categoryLabel":"Pháp khí cổ quái","phamCap":"Không rõ","soHuu":["Nữ tử áo trắng (hậu nhân Trưởng lão Yểm Nguyệt tông)"],"trangThai":"dang-co","blurb":"Gương nhỏ cổ quái phóng thanh quang bao lấy pháp khí và pháp thuật đối phương, khiến chúng lơ lửng quần đảo giữa không trung không thể hạ xuống, như bị cấm chế.","detail":"Pháp khí cổ quái của nữ áo trắng, một trong nhiều bảo vật truyền lại từ Trưởng lão Yểm Nguyệt tông. Khi lật ra, gương phóng thanh quang bao lấy sáu thanh kim nhận của Hàn Lập cùng hỏa xà của nữ áo vàng, khiến chúng lơ lửng quần đảo giữa không trung không hạ xuống được. Hạn chế: mỗi lần chỉ chế ngự một vùng, kéo dài nửa khắc rồi phải thu hồi.","nguon":["@c0186"]},{"id":"dai-hoa-cau-phu-luc","name":"Đại hỏa cầu phù lục","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Nữ tử áo trắng (hậu nhân Trưởng lão Yểm Nguyệt tông)"],"trangThai":"da-dung","blurb":"Phù lục hỏa hệ nữ áo trắng dùng đánh nổ tan nửa trên cây cổ thụ nơi Hàn Lập ẩn thân.","detail":"Nữ áo trắng đánh ra một quả Đại hỏa cầu từ phù lục, phá tan nửa trên cây cổ thụ trong nháy mắt thành tro bụi để buộc Hàn Lập lộ diện, nhưng hắn đã kịp né ra sau gốc cây.","nguon":["@c0186"]},{"id":"thanh-tac","name":"Thanh Tác","cn":"","category":"linh-khi","categoryLabel":"Pháp khí","phamCap":"Thượng phẩm pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thượng phẩm pháp khí của Hàn Lập, sợi roi màu xanh di chuyển như linh xà vô thanh vô tức.","detail":"Pháp khí hình sợi roi màu xanh của Hàn Lập, khi thi triển di chuyển như linh xà, vô thanh vô tức. Hàn Lập dùng nó trói chặt nữ tử áo trắng Yểm nguyệt tông cùng vòng bảo hộ thành một cái kén. Sau đó bị luồng hoàng quang từ phù bảo của Phong Nhạc bắn xuyên qua.","nguon":["@c0187"]},{"id":"ngan-cau-han-lap","name":"Ngân câu","cn":"","category":"linh-khi","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"hong","blurb":"Pháp khí ngân quang lập lòe của Hàn Lập, bị dịch thể ăn mòn hư hỏng.","detail":"Pháp khí phát ánh ngân quang lập lòe của Hàn Lập. Trong trận đánh với nữ tử áo trắng, ngân câu bị dịch thể màu hồng phun ra từ thủy tinh cầu ăn mòn đến mức đổi màu thủng lỗ chỗ, linh khí không còn, hư hỏng không dùng được nữa.","nguon":["@c0187"]},{"id":"thuy-tinh-cau-mau-hong","name":"Thủy tinh cầu màu hồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo","soHuu":["Nữ tử áo trắng (Yểm nguyệt tông)"],"trangThai":"mat","blurb":"Pháp bảo của nữ tử áo trắng, phun dịch thể màu hồng phấn ăn mòn pháp khí và tạo vòng bảo hộ.","detail":"Pháp bảo hình cầu thủy tinh màu hồng của nữ tử áo trắng Yểm nguyệt tông, lơ lửng trên đầu. Khi kích hoạt bằng thủ ấn, nó phun dịch thể màu hồng phấn tạo vòng bảo hộ rộng cỡ một trượng và ăn mòn pháp khí đối phương. Sau khi nữ tử chết, thủy tinh cầu rơi xuống đất; Hàn Lập phóng hỏa cầu ngăn không cho Phong Nhạc thu lấy.","nguon":["@c0187"]},{"id":"tam-guong-nho-nu-ao-trang","name":"Tấm gương nhỏ","cn":"","category":"linh-khi","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":["Nữ tử áo trắng (Yểm nguyệt tông)"],"trangThai":"mat","blurb":"Pháp khí phòng ngự của nữ tử áo trắng, ngăn được kim nhận của Hàn Lập.","detail":"Pháp khí tấm gương nhỏ của nữ tử áo trắng Yểm nguyệt tông, ngăn cản được kim nhận của Hàn Lập khiến nàng tự đắc. Sau khi nữ tử bị Phong Nhạc giết, tấm gương rơi xuống đất; Hàn Lập không cho Phong Nhạc thu lấy.","nguon":["@c0187"]},{"id":"tieu-dao-hoang-quang","name":"Tiểu đao hoàng quang","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Phù bảo (uy năng pháp bảo)","soHuu":["Phong Nhạc"],"trangThai":"dang-co","blurb":"Phù bảo của Phong Nhạc, tiểu đao cổ quái tỏa hoàng quang, một đòn giết chết nữ tử áo trắng.","detail":"Phù bảo hình tiểu đao cổ quái của Phong Nhạc: chuôi dài cỡ một thước, lưỡi dài ba bốn tấc, thân trong suốt tỏa hoàng quang chói mắt. Khi thi triển, linh khí bạo phát kinh người; một luồng hoàng quang bắn xuyên Thanh Tác, vòng bảo hộ và cả nữ tử áo trắng, giết chết nàng ngay tại chỗ. Hàn Lập xác nhận nó là phù bảo có đầy đủ uy năng của một pháp bảo, giống Kim quang chuyên của hắn.","nguon":["@c0187"]},{"id":"kim-quang-chuyen-han-lap","name":"Kim quang chuyên","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Phù bảo (uy lực cao)","soHuu":["Hàn Lập"],"trangThai":"Do Hàn Lập nắm giữ; chưa xuất ra trong trận đấu với Phong Nhạc","blurb":"Phù bảo của Hàn Lập với lực phá hoại kinh người nhưng chậm chạp, chỉ phát huy khi vây khốn được đối thủ.","detail":"Phù bảo do Hàn Lập nắm giữ, lực phá hoại vượt xa phi kiếm thông thường: người tu tiên cấp thấp một khi bị trúng thì dù có nhiều pháp khí bảo hộ cũng khó thoát chết. Tuy nhiên nó có nhược điểm rõ ràng — phải hấp thụ một lượng lớn pháp thuật của người sử dụng mới có thể khu sử được, đồng thời tốc độ và độ linh hoạt kém, khó đuổi kịp đối thủ thân pháp nhanh. Vì thế nó chỉ thật sự hữu dụng khi đã trói buộc hoặc vây khốn được địch nhân từ trước, tính chất tương tự Đại ấn của cao thủ Kết đan kỳ Thiên khuyết bảo — uy lực lớn nhưng nặng nề chậm rãi. Trong trận với Phong Nhạc, Hàn Lập từng định xuất nó ra nhưng nhận ra thân pháp đối phương quá nhanh khiến kế đánh lén khó thành."},{"id":"thien-loi-tu","name":"Thiên Lôi Tử","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Sát thủ tối cường","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Đòn sát thủ tối cường của Hàn Lập, viên châu màu lam bùng nổ sáng trắng vô thanh khiến đối thủ hóa cát bụi.","detail":"Ngoại hình là viên châu màu lam nhỏ hơn Hỗn Nguyên Châu thường, giấu lẫn trong đám Hỗn Nguyên Châu để làm nhiễu loạn tư tưởng đối phương; khi chạm vòng bảo hộ bùng nổ luồng sáng trắng vô thanh vô tức, khiến Phong Nhạc chết và hóa thành cát bụi chỉ còn hai nửa chân đi giày.","nguon":["@c0189"]},{"id":"hoang-la-tan","name":"Hoàng La Tán","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Phòng ngự cực cao","soHuu":["Phong Nhạc"],"trangThai":"mat","blurb":"Pháp khí phòng ngự của Phong Nhạc, xuất vòng hào quang màu xanh bao quanh người, lực phòng ngự vượt Phi Thiên Thuẫn.","detail":"Xuất một vòng hào quang màu xanh bao quanh người, lực phòng ngự cực cao khiến kim nhận của Hàn Lập nổ bắn ngược lại; có thể dùng vô số lần nên Phong Nhạc coi trọng hơn cả phù bảo tiểu đao (phù bảo chỉ dùng vài lần thành phế thải). Từ khi được Hoàng La Tán, Phong Nhạc chưa từng bị tu tiên giả cấp thấp làm bị thương.","nguon":["@c0189"]},{"id":"thanh-giao-ky","name":"Thanh Giao kỳ","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Tinh phẩm bậc trung","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lá cờ màu xanh có hình Thanh Giao, tụ linh quang màu xanh thanh thế lớn, Hàn Lập dùng làm nghi binh.","detail":"Lá cờ màu xanh có hình Thanh Giao dơ nanh múa vuốt, tụ linh quang màu xanh với thanh thế lớn; Hàn Lập dùng để thu hút chú ý và đề phòng của Phong Nhạc, tạo che chắn cho Thiên Lôi Tử ẩn trong đám Hỗn Nguyên Châu.","nguon":["@c0189"]},{"id":"hon-nguyen-chau","name":"Hỗn Nguyên Châu","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Trung phẩm","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Pháp khí tầm thường ai cũng biết, tiểu hồ lô đen phun bảy tám viên cầu đen; Hàn Lập dùng che giấu Thiên Lôi Tử.","detail":"Pháp khí tầm thường được ai cũng biết, chỉ miễn cưỡng xếp trung phẩm; xuất ra từ tiểu hồ lô màu đen, phun bảy tám viên cầu màu đen bay về đối phương. Hàn Lập dùng làm bình phong che giấu Thiên Lôi Tử màu lam.","nguon":["@c0189"]},{"id":"phu-bao-tieu-dao-hoang-mang-phong-nhac","name":"Phù bảo tiểu đao (hoàng mang)","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Phù bảo","soHuu":["Phong Nhạc"],"trangThai":"mat","blurb":"Tiểu đao màu vàng của Phong Nhạc, nhanh như thiểm điện vây quanh tấn công tìm sơ hở.","detail":"Tiểu đao màu vàng phát hoàng mang, được Phong Nhạc toàn lực chỉ huy vây quanh Hàn Lập tấn công nhanh như thiểm điện; phù bảo chỉ dùng được vài lần rồi thành phế thải nên Phong Nhạc coi trọng kém hơn Hoàng La Tán.","nguon":["@c0189"]},{"id":"dap-van-ngoa","name":"Đạp vân ngoa","aliases":["Đôi giày pháp khí (Ô Ngoa)","Linh ngoa","Ô Ngoa"],"category":"linh-khi","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Đôi giày da yêu thú màu đen, nhẹ mềm dẻo dai, mở khóa thân pháp cực tốc; vốn của Phong Nhạc, Hàn Lập chiếm được.","detail":"Giày da đen làm từ da yêu thú, nhẹ mềm dẻo dai, ẩn phát linh khí; sống sót nguyên vẹn dưới Hỏa đạn thuật mà không dấu cháy nên bị nhận ra là pháp khí. Cho phép người mang bước một bước nhỏ liền phiêu ra ngoài một trượng, nhanh hơn Ngự Phong quyết nhiều, tạo nhiều ảo ảnh; kết hợp La Yên bộ và Ngự Phong quyết giúp Hàn Lập hóa gió, thoát khỏi cả Thiên Nhãn thuật chỉ hiện như bóng nhàn nhạt. Đây chính là bí mật thân pháp quỷ dị nhanh như lôi điện của Phong Nhạc; tốc độ này chỉ duy trì thời gian ngắn do thân thể còn miễn cưỡng.","nguon":["@c0190"]},{"id":"phu-bao-tieu-dao-nu-ao-vang","name":"Phù bảo tiểu đao (nữ áo vàng)","aliases":["Phù bảo hình tiểu đao"],"category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phù lục của nữ tử áo vàng, sau khi chủ chết khôi phục thành phù bảo hình tiểu đao.","detail":"Vốn là phù lục của nữ tử áo vàng; do chủ đã chết nên khôi phục thành phù bảo hình tiểu đao. Hàn Lập nhặt được cùng gương nhỏ và Thủy tinh cầu.","nguon":["@c0190"]},{"id":"cu-kiem-mau-xanh-mong-de-tu","name":"Cự kiếm màu xanh","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Mông đệ tử (Hắc y nhân)"],"trangThai":"dang-co","blurb":"Cự kiếm màu xanh của Mông đệ tử Cự Kiếm môn, dùng chống đỡ thế công hỏa lang rồi một kiếm chém chết yêu thú.","detail":"Trong trận diệt Hỏa lang ba mắt ở vùng phía tây khu trung tâm, Mông đệ tử dùng cự kiếm màu xanh gánh đại bộ phận thế công của yêu thú, sau đó một kiếm chém xuống đầu nó kết liễu.","nguon":["@c0191"]},{"id":"phu-luc-mau-lam-bang-truy","name":"Phù lục màu lam (phù Băng Trùy)","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Nữ đệ tử Yểm Nguyệt tông (Yểm Nguyệt song kiều)"],"trangThai":"da-dung","blurb":"Phù lục màu lam của nữ đệ tử Yểm Nguyệt tông, biến thành mây đen hơn mười trượng và phóng vô số băng trùy phủ dày một vùng cát.","detail":"Nữ đệ tử Yểm Nguyệt tông ném phù lục lam ra sau lưng; nó hóa thành đám mây đen hơn mười trượng, hạ nhiệt vùng trời rồi phóng vô số băng trùy lớn cắm dày đặc, khiến vùng cát trở nên trong suốt nhưng vẫn không lộ mục tiêu ẩn nấp.","nguon":["@c0191"]},{"id":"khan-lua-mau-vang-ham-van-chi","name":"Khăn lụa màu vàng (hoàng cân)","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Hạm Vân Chi"],"trangThai":"dang-co","blurb":"Khăn lụa màu vàng có hào quang chớp động mà cô gái áo lục nắm chặt, tựa hồ không phải vật phàm.","detail":"Khi trồi lên khỏi cát với vết thương ở vai, cô gái áo lục Linh Thú sơn nắm chặt trong tay một khăn lụa màu vàng mặt trên hào quang chớp động, dường như là pháp bảo phi phàm nàng liều mạng giữ gìn — có thể là nguyên nhân nàng bị Yểm Nguyệt tông truy sát.","nguon":["@c0191"]},{"id":"hoa-long-thao","name":"Hỏa Long thảo","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":[],"trangThai":"dang-co","blurb":"Kỳ trân dị thảo màu đỏ mọc sau thi thể Hỏa lang ba mắt, mục tiêu ba tu sĩ hợp sức hái và chia đều.","detail":"Mấy gốc cây cỏ nhỏ màu đỏ mọc sau thi thể Hỏa lang ba mắt tại hố đất vùng phía tây khu trung tâm; ba tu sĩ Cự Kiếm môn, Hướng Chi Lễ và Lý đạo trưởng hợp sức diệt yêu để hái và dự định chia đều, dù Mông đệ tử ngầm định trở mặt độc chiếm.","nguon":["@c0191"]},{"id":"hoa-xa-thuat-phu-luc","name":"Hỏa xà thuật (phù lục)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phù lục hỏa hệ, kích phát tạo lửa thiêu đốt mục tiêu.","detail":"Phù lục hỏa hệ Hàn Lập rút ra định kích phát để thiêu chết hai con phi xà trong khu trung tâm thí luyện. Chưa kịp ném thì kẻ địch kêu dừng tay nên hắn chần chừ, một tay vẫn đặt cẩn thận tại túi trữ vật.","nguon":["@c0192"]},{"id":"dai-bang-truy","name":"Đại băng trùy","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Pháp bảo băng hệ hình trùy, đâm xuyên vật thể.","detail":"Vật dùng đâm xuyên tứ chi ba tử thi trên bức tường đá gần cửa đồng, đóng đinh họ xếp thành chữ đại như một đòn giết gà dọa khỉ lập uy.","nguon":["@c0192"]},{"id":"nguyet-duong-bao-chau","name":"Nguyệt dương bảo châu","cn":"月阳宝珠","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thất đại phái"],"trangThai":"dang-co","blurb":"Bảo châu do tu sĩ Yểm Nguyệt tông luyện chế, không thể tấn công cũng không phòng ngự, chỉ phóng kỳ quang khắc chế sương mù độc chướng để dễ tiến vào cấm địa.","detail":"Nhờ Nguyệt dương bảo châu khắc chế sương mù, Yểm Nguyệt tông từng độc chiếm thu hoạch cấm địa, luyện nhiều Trúc Cơ đan và vươn lên thành Việt quốc đệ nhất tu tiên phái. Sau khi lục đại phái tìm tới ép, bảo châu trở thành vật chung của thất đại phái, các phái thay phiên nắm giữ và giám sát lẫn nhau khi khu trừ sương mù.","nguon":["@c0194","@c0195"]},{"id":"binh-ngoc-phun-doc-vu","name":"Bình ngọc phun độc vụ","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng phẩm pháp khí (phụ trợ)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thượng phẩm pháp khí phụ trợ phun ra độc vụ màu xanh biếc mênh mông; uy lực yếu vì người tu tiên có ngũ hành hộ tráo chống được, nhưng Hàn Lập chọn để che mắt địch nhân.","detail":"Một trong ba kiện thượng phẩm pháp khí Hàn Lập chọn ra từ chiến lợi phẩm. Bình ngọc phun ra độc vụ màu xanh biếc mênh mông làm nhiễu loạn và khiến người trúng độc, song thực chất uy lực yếu vì người tu tiên đều có ngũ hành hộ tráo chống lại được. Hàn Lập chọn nó vì độc vụ có thể tạm che mắt địch nhân, làm công cụ nghi binh.","nguon":["@c0195"]},{"id":"phi-dao-thuong-pham-han-lap","name":"Phi đao (thượng phẩm)","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng phẩm pháp khí (tấn công)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Một trong ba kiện thượng phẩm pháp khí tấn công có uy lực lớn nhất Hàn Lập chọn ra từ chiến lợi phẩm.","detail":"Thanh phi đao là một trong ba kiện Hàn Lập chọn từ 11 món thượng phẩm pháp khí thu được, có uy lực tấn công lớn nhất.","nguon":["@c0195"]},{"id":"kim-bat-thuong-pham-han-lap","name":"Kim bạt (thượng phẩm)","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng phẩm pháp khí (tấn công)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Một trong ba kiện thượng phẩm pháp khí tấn công có uy lực lớn nhất Hàn Lập chọn ra từ chiến lợi phẩm.","detail":"Chiếc kim bạt là một trong ba kiện Hàn Lập chọn từ 11 món thượng phẩm pháp khí thu được, có uy lực tấn công lớn nhất.","nguon":["@c0195"]},{"id":"binh-nho-than-bi-han-lap","name":"Cái bình nhỏ thần bí","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bảo vật thần bí của Hàn Lập, ban đêm dùng nuôi dưỡng cây con linh dược giúp chúng trưởng thành nhanh nhiều lần.","detail":"Cái bình nhỏ thần bí là nền tảng cốt lõi trong kế hoạch hái dược của Hàn Lập. Hắn dự tính sau khi hái các cây con linh dược mà người khác coi vô dụng, sẽ dùng bình này ban đêm nuôi dưỡng cho chúng trưởng thành nhiều lần, biến cây con thành linh dược đủ tuổi để luyện Trúc Cơ đan.","nguon":["@c0196"]},{"id":"huyet-tuyen-giao-noi-dan","name":"Huyết Tuyến giao nội đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược / Vật phẩm","phamCap":"Không rõ","soHuu":["Phù Vân Tử"],"trangThai":"dang-co","blurb":"Viên nội đan mà đạo sĩ Thanh Hư Phù Vân Tử đặt cược, rất khó có được, gần như tiêu tốn toàn bộ tiền tài của hắn.","detail":"Viên nội đan của Huyết Tuyến giao được Phù Vân Tử đặt cược trong cuộc đấu thí luyện cấm địa. Loại nội đan này rất khó kiếm, khiến hắn tiêu tốn gần hết tiền tài mới có được, nên khi Khung lão quái nhúng tay đánh cược hắn càng lo lắng được mất.","nguon":["@c0196","@c0211"]},{"id":"tu-hau-hoa","name":"Tử Hầu hoa","cn":"","category":"nguyen-lieu","categoryLabel":"Linh dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Loại linh dược sản sinh ở sơn động bí mật; trăm năm trước bị hái sạch, nay chỉ còn cây con — mục tiêu hái dược của Hàn Lập.","detail":"Tử Hầu hoa là thảo dược sinh trưởng ở một sơn động bí mật trong cấm địa núi lửa. Trăm năm trước nơi này đã bị hái, nay chỉ còn cây con chưa trưởng thành mà người khác coi là vô dụng. Hàn Lập nhắm vào những cây con này để nuôi dưỡng thành linh dược đủ tuổi.","nguon":["@c0196"]},{"id":"buom-vang-chung-ngo","name":"Bướm vàng truy tung","cn":"","category":"khac","categoryLabel":"Vật / Pháp khí truy tung","phamCap":"Không rõ","soHuu":["Chung Ngô"],"trangThai":"dang-co","blurb":"Mười mấy con bướm vàng Chung Ngô thả vào rừng núi cấm địa để truy tung Hàn Lập.","detail":"Sau khi Hàn Lập vào cấm địa, Chung Ngô thả ra mười mấy con bướm vàng bay vào rừng núi, dùng để truy tung theo dấu Hàn Lập trước khi thong thả đi theo với ý ám toán.","nguon":["@c0196"]},{"id":"nguyet-quang-thach","name":"Nguyệt Quang thạch","category":"khac","categoryLabel":"Vật chiếu sáng","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Viên đá to bằng quả trứng gà phát ánh sáng trắng hòa nhã, Hàn Lập dùng soi đường trong động tối.","detail":"Khi hiện ra, Nguyệt Quang thạch phát ánh sáng trắng hòa nhã chiếu rõ khu vực phụ cận. Hàn Lập lấy từ túi trữ vật để soi đường trong bí động tối. Vì ánh sáng biến hắn thành đích ngắm, hắn tạo vòng bảo hộ thổ thuộc tính rồi mới tiếp tục tiến sâu.","nguon":["@c0197"]},{"id":"phi-dao-mau-xanh-han-lap","name":"Phi đao màu xanh","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thanh phi đao xanh sáng chói Hàn Lập điều khiển cắt xúc tu con rết.","detail":"Cuối chương, Hàn Lập khoát tay xuất ra một thanh phi đao màu xanh sáng chói cùng đạo kim quang hình tròn, trực tiếp cắt về phía hai xúc tu thô dài của con rết.","nguon":["@c0197"]},{"id":"luoi-dao-bay-han-lap","name":"Lưỡi dao sắc bén (bẫy)","category":"phap-bao","categoryLabel":"Pháp khí ẩn","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lưỡi dao cực kỳ sắc Hàn Lập bố trí ẩn trong thông đạo làm cạm bẫy xẻ bụng con rết.","detail":"Hàn Lập bố trí một lưỡi dao cực kỳ sắc bén trong thông đạo. Khi con rết đuổi theo hắn tới nơi, bụng (bộ phận yếu nhất) bị lưỡi dao bất tri bất giác xẻ banh ra, độc huyết đen tuôn ồ ạt, tạo cơ hội cho hắn phản kích.","nguon":["@c0197"]},{"id":"phi-xoa-xanh-chau-tu-vang","name":"Phi xoa xanh và châu tử vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Đỉnh cấp","soHuu":["Thanh niên áo lam (đệ tử Thiên Khuyết bảo)"],"trangThai":"dang-co","blurb":"Pháp khí đỉnh cấp của thanh niên áo lam Thiên Khuyết bảo, linh quang chói mắt.","detail":"Bộ pháp khí đỉnh cấp gồm phi xoa màu xanh và châu tử màu vàng của thanh niên áo lam, tỏa linh quang chói mắt, dùng để tranh giành linh dược.","nguon":["@c0198"]},{"id":"quai-truong-lao-gia-ao-xanh","name":"Quải trượng (lão giả áo xanh)","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Lão giả áo xanh (cầm quải trượng)"],"trangThai":"dang-co","blurb":"Pháp khí của lão giả áo xanh, hóa thành thanh quang cực nhanh chặn đường.","detail":"Cây quải trượng của lão giả áo xanh, khi phóng ra hóa thành thanh quang cực nhanh chặn đường thanh niên áo lam định cướp linh dược.","nguon":["@c0198"]},{"id":"thanh-linh-tan","name":"Thanh Linh tán","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thuốc bột giải độc, trừ cảm giác choáng váng do độc huyết lan trong không khí.","detail":"Hàn Lập phục dùng Thanh Linh tán để giải độc tính độc huyết bốc mùi từ con rết chết, trừ cảm giác choáng váng.","nguon":["@c0198"]},{"id":"thien-linh-qua","name":"Thiên Linh quả","cn":"","category":"nguyen-lieu","categoryLabel":"Linh dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Loại quả linh dược chưa thành thục Hàn Lập dự định tiếp tục hái.","detail":"Thiên Linh quả là loại linh quả chưa thành thục mà Hàn Lập tiếp tục sưu tập tại cấm địa.","nguon":["@c0198"]},{"id":"lac-tran-chau","name":"Lạc Trần châu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập","Mã Vân Long"],"trangThai":"dang-co","blurb":"Pháp khí thành danh của Mã Vân Long, nay ở trong tay Hàn Lập. Là bằng chứng khiến đạo sĩ nhận ra và bảo vệ Hàn Lập khỏi bị lão giả họ Lý sát hại.","detail":"Pháp khí thành danh của Mã Vân Long — cường giả Thiên Khuyết bảo. Hiện Hàn Lập cầm giữ, vô tình khiến người khác nhầm hắn có quan hệ lớn với Mã Vân Long, nhờ đó lão giả họ Lý bỏ ý định cướp pháp khí và không dám động vào Hàn Lập.","nguon":["@c0199"]},{"id":"kim-thu-tran-dai-ca","name":"Kim thư","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Trần đại công tử"],"trangThai":"dang-co","blurb":"Quyển sách kim quang rực rỡ của Trần đại ca, kết hợp Ngân bút tạo uy lực lớn dọa lui đối thủ.","detail":"Pháp khí của Trần đại công tử, hình quyển sách phát ra kim quang rực rỡ. Phối hợp cùng Ngân bút thi triển ngân phù tạo uy lực lớn, khiến thanh niên Hóa Đao ổ chống không nổi phải nhận thua.","nguon":["@c0199"]},{"id":"ngan-but-tran-dai-ca","name":"Ngân bút","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Trần đại công tử"],"trangThai":"dang-co","blurb":"Cây bút lớn bằng gỗ ngân quang lập lòe của Trần đại ca, dùng thi triển ngân phù.","detail":"Pháp khí của Trần đại công tử, là cây bút lớn bằng gỗ tỏa ngân quang lập lòe. Dùng thi triển ngân phù tạo vô số điểm sáng như sao đầy trời, kết hợp Kim thư tạo uy lực lớn.","nguon":["@c0199"]},{"id":"thanh-giao-ky-luc-gia","name":"Thanh Giao kỳ (Lục gia)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đỉnh cấp","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp khí đỉnh cấp vốn của tiểu tử Lục gia, bị Hàn Lập đoạt. Trần đại ca dùng làm manh mối truy tìm người cứu thất muội.","detail":"Pháp khí đỉnh cấp từng thuộc về tiểu tử Lục gia, đã bị Hàn Lập đoạt. Trần đại công tử biết người cứu thất muội có Thanh Giao kỳ nên lấy đó làm manh mối truy tìm.","nguon":["@c0199"]},{"id":"phi-kiem-lam-vang-tran-thu-muoi","name":"Phi kiếm lam-vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Trần sư muội"],"trangThai":"dang-co","blurb":"Hai kiện phi kiếm một lam một vàng của Trần thất muội.","detail":"Hai kiện phi kiếm, một màu lam một màu vàng, là pháp khí của Trần thất muội — nữ tử thực lực yếu nhất trong phe họ Trần khi tranh linh thảo.","nguon":["@c0199"]},{"id":"phi-xa-mieng-tho-chung-ngo","name":"Phi xà miệng thô","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chung Ngô"],"trangThai":"dang-co","blurb":"Phi xà miệng to như cái bát của Chung Ngô, đi kèm bầy ong vàng to lớn.","detail":"Pháp khí của Chung Ngô (Linh Thú sơn), là phi xà có miệng to như cái bát, chiến đấu cùng bầy ong vàng to lớn.","nguon":["@c0199"]},{"id":"trai-do-dai-thu-rung","name":"Trái đỏ trên đại thụ","cn":"","category":"khac","categoryLabel":"Linh quả","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Cây đại thụ đỏ như lửa trong rừng rậm mang vài trái đỏ to bằng nắm đấm.","detail":"Trong rừng rậm có cây đại thụ đỏ như lửa, mang vài trái đỏ to bằng nắm đấm; cô gái áo lục điều khiển tiểu điêu trắng đấu quái xà hai đầu bảo vệ nơi này.","nguon":["@c0199"]},{"id":"tieu-dieu-trang-nu-ao-luc","name":"Tiểu điêu trắng","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ","soHuu":["Cô gái áo lục"],"trangThai":"dang-co","blurb":"Điểu nhỏ màu trắng cô gái áo lục điều khiển gian nan đấu quái xà hai đầu.","detail":"Tiểu điêu màu trắng của cô gái áo lục trong rừng rậm, được điều khiển gian nan đấu với con quái xà hai đầu cạnh cây đại thụ đỏ.","nguon":["@c0199"]},{"id":"vien-hoan-mau-phan-hong","name":"Viên hoàn màu phấn hồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo cao cấp","soHuu":["Cô gái áo trắng (Sư tổ Yểm Nguyệt tông)"],"trangThai":"dang-co","blurb":"Viên hoàn to bằng ngón cái từ miệng cô gái áo trắng phun ra, đón gió phồng to bằng cái đầu, phát âm ông ông, chứa linh lực khổng lồ.","detail":"Pháp bảo của Sư tổ Yểm Nguyệt tông. Ban đầu chỉ to bằng ngón cái, khi phun ra đón gió phồng to bằng cái đầu, phát ra âm thanh ông ông, ẩn chứa linh lực khổng lồ. Dùng để dẫn dụ yêu thú đỉnh cấp Bích Thủy ngạc ra khỏi mặt nước, đồng thời ngăn được hơn phân nửa lực công kích của yêu thú, giúp diệt nó mà không tổn thương đệ tử nào.","nguon":["@c0200"]},{"id":"khan-lua-hoang-quang-ham-van-chi","name":"Khăn lụa hoàng quang","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí đỉnh cấp","soHuu":["Hạm Vân Chi"],"trangThai":"dang-co","blurb":"Thủ đoạn phòng hộ duy nhất của cô gái áo lục, lóe hoàng quang nhưng ảm đạm vô sắc, bị cự kiếm bạc áp đảo.","detail":"Pháp khí đỉnh cấp mà cô gái áo lục Linh Thú sơn dùng liều chết chống hán tử Cự Kiếm môn. Khi thi triển lóe hoàng quang song ảm đạm vô sắc, là thủ đoạn phòng hộ duy nhất của nàng, khó khăn chống đỡ cự kiếm màu bạc của đối thủ.","nguon":["@c0200"]},{"id":"liet-duong-hoa","name":"Liệt Dương hoa","cn":"","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Linh dược","soHuu":[],"trangThai":"dang-co","blurb":"Loại linh dược bên trong thạch điện gần đỉnh núi mà cô gái áo lục đòi hán tử Cự Kiếm môn đưa cho vài hạt.","detail":"Linh dược quý mọc bên trong thạch điện nhỏ gần đỉnh núi trong cấm địa. Cô gái áo lục Linh Thú sơn quyết liều chết đòi hán tử Cự Kiếm môn cho vài hạt, chết cũng không tránh ra.","nguon":["@c0200","@c0203"]},{"id":"kim-nhan","name":"Kim nhận","aliases":["Kim tử nhận","Tử nhận","Mẫu nhận","Bảy tử nhận"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đỉnh cấp pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bộ phi nhận màu vàng của Hàn Lập gồm mẫu nhận điều khiển và bảy tử nhận; được Vũ Si đánh giá là một bộ đỉnh cấp pháp khí.","detail":"Một thanh phi nhận màu vàng bay ra ngăn ngân kiếm cách đầu cô gái áo lục một trượng mà không bị hủy, tạo màn kim quang bảo hộ. Khi giao đấu, Hàn Lập rung mẫu nhận, bảy thanh tử nhận còn lại từ túi trữ vật bay ra biến thành bảy đạo kim mang, quần với cự kiếm màu bạc như bảy con kim xà quấn lấy một con cự mãng. Vũ Si đoán đây là một bộ đỉnh cấp pháp khí và khiêu chiến để đoạt lấy.","nguon":["@c0201"]},{"id":"khan-lua-ham-van-chi","name":"Khăn lụa (pháp khí Hạm Vân Chi)","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hạm Vân Chi"],"trangThai":"hong","blurb":"Pháp khí khăn lụa của cô gái áo lục, hóa thành bánh xe để đón kiếm, bị ngân kiếm chém nát thành mảnh nhỏ.","detail":"Khi bị Vũ Si tấn công, cô gái áo lục biến khăn lụa thành bánh xe để chống đỡ, nhưng lập tức bị cự kiếm màu bạc một kiếm chém nát thành những mảnh nhỏ.","nguon":["@c0201"]},{"id":"thanh-ngung-kinh","name":"Thanh Ngưng kính","cn":"","aliases":["Gương nhỏ (nữ nhân nhiều bảo vật)"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đỉnh cấp pháp khí (hộ thân)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Gương nhỏ hộ thân pháp khí của Yểm Nguyệt song kiều, rót linh lực chiếu ánh sáng xanh vây khốn pháp khí địch giữa không trung.","detail":"Cái gương nhỏ Hàn Lập đoạt được từ nữ nhân nhiều bảo vật (từ tay Phong Nhạc). Rót linh lực vào, gương chiếu ra ánh sáng xanh, vây khốn ngân kiếm cùng các kim nhận còn lại giữa không trung không thể nhúc nhích. Đại hán chân trần kinh hãi nhận ra đây là Thanh Ngưng kính — hộ thân pháp khí của Yểm Nguyệt song kiều, khiến việc sở hữu nó trở thành họa danh tính có thể chuốc truy sát của Trưởng lão Kết đan kỳ Yểm Nguyệt tông.","nguon":["@c0202"]},{"id":"phi-dao-mau-lam-thuong-pham","name":"Phi đao màu lam (thượng phẩm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thượng phẩm pháp khí","soHuu":["Hàn Lập"],"trangThai":"hong","blurb":"Thượng phẩm pháp khí Hàn Lập bắn về phía đại hán, bị hút vào ngân kiếm nghiền nát.","detail":"Một trong hai thượng phẩm pháp khí Hàn Lập vỗ túi trữ vật lấy ra bắn về phía đại hán chân trần. Vừa tiến vào vùng sáng bạc đã bị cự kiếm màu bạc luân chuyển cuốn vào cơn lốc xoáy nghiền nát.","nguon":["@c0202"]},{"id":"phi-bat-mau-vang-thuong-pham","name":"Phi bạt màu vàng (thượng phẩm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thượng phẩm pháp khí","soHuu":["Hàn Lập"],"trangThai":"hong","blurb":"Thượng phẩm pháp khí bắn cùng phi đao, cũng bị lốc xoáy ngân kiếm nghiền nát.","detail":"Cùng phi đao màu lam, Hàn Lập bắn phi bạt màu vàng về phía đại hán. Cả hai kiện vừa tiến vào bên trong đã bị cự kiếm màu bạc cấp tốc luân chuyển cuốn vào cơn lốc xoáy nghiền nát.","nguon":["@c0202"]},{"id":"vong-tran-hoan","name":"Vong Trần hoàn","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Viên thuốc sắc đỏ như lửa Hàn Lập tiện tay tự chế, dùng kết hợp Vô ưu châm pháp để xóa trí nhớ hoàn mỹ.","detail":"Vong Trần hoàn là viên thuốc có sắc đỏ như lửa, trước đây Hàn Lập tiện tay luyện chế. Khi dùng, hắn nhét viên thuốc vào miệng đối phương rồi kết hợp Vô ưu châm pháp để xóa trí nhớ đạt mức hoàn mỹ; tuy có chút nguy hiểm nhưng không gây vấn đề lớn. Trong cấm địa Huyết sắc thí luyện, hắn dùng nó cùng Vô ưu châm pháp để xóa trí nhớ nửa ngày của Hạm Vân Chi.","nguon":["@c0203"]},{"id":"vo-uu-cham-bo-ngan-cham","name":"Vô ưu châm (bộ ngân châm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bộ ngân châm đựng trong hộp bạc lớn bằng bàn tay, vật Hàn Lập từng dùng châm cứu tại Thất huyền môn.","detail":"Bộ ngân châm được cất trong một hộp bạc lớn bằng bàn tay, là vật Hàn Lập từng dùng để châm cứu trong quãng thời gian ở Thất huyền môn. Đây là dụng cụ để hắn thi triển Vô ưu châm pháp; khi lấy ra, hắn hồi tưởng lại Mặc đại phu, Lịch Phi Vũ cùng cuộc sống quá khứ tại Thải hà sơn và Thần thủ cốc.","nguon":["@c0203"]},{"id":"hop-vang-kim-hap-dam-lay","name":"Hộp vàng (kim hạp)","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"Phi phàm (không phải vật phàm)","soHuu":[],"trangThai":"dang-co","blurb":"Chiếc hộp vàng dài chừng một hai trượng lơ lửng trên tiểu đình bạch ngọc giữa đầm lầy, đóng chặt, ngoài có kim quang lưu động — mục tiêu tranh đoạt.","detail":"Ở trung gian thế giới đầm lầy dưới địa đạo có một tiểu đình bạch ngọc, trên không lơ lửng một hộp vàng dài chừng một hai trượng, rộng cỡ nửa trượng, đang đóng chặt, bên ngoài có kim quang lưu động — rõ ràng không phải vật phàm. Nó trở thành tâm điểm tranh đoạt giữa Hàn Lập và đám Yểm Nguyệt tông tiến vào đầm lầy.","nguon":["@c0204"]},{"id":"chu-tuoc-hoan","name":"Chu tước hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Cô gái áo trắng (Sư tổ Yểm Nguyệt tông)"],"trangThai":"dang-co","blurb":"Pháp bảo hình vòng tròn của cô gái sư tổ Yểm Nguyệt tông, biến lớn như căn phòng, luân chuyển thành lửa đỏ tụ mấy trăm hỏa cầu.","detail":"Chu tước hoàn là pháp bảo hình vòng tròn được cô gái sư tổ Yểm Nguyệt tông phun ra, bay lên không trung đầm lầy, biến lớn như căn phòng và luân chuyển thành ngọn lửa đỏ rực tụ thành mấy trăm hỏa cầu to bằng nắm tay, làm nhiệt độ tăng cao. Có thể biến mất rồi hiện thân, chụp giam thân yêu thú Mặc Giao trong lửa đỏ, kết hợp với Hồng viêm thuật để bùng nổ sức mạnh. Việc khu sử được pháp bảo này khiến Hàn Lập nghĩ cô gái phải là Kết đan kỳ.","nguon":["@c0205"]},{"id":"cai-hop-vat-can-tim-yem-nguyet-tong","name":"Cái hộp (vật cần tìm)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Cô gái áo trắng (Sư tổ Yểm Nguyệt tông)"],"trangThai":"dang-co","blurb":"Vật cô gái sư tổ Yểm Nguyệt tông lẩm bẩm rằng thứ thật sự cần tìm nằm bên trong “cái hộp này”, còn những thứ trước chỉ là rác rưởi.","detail":"Cô gái sư tổ Yểm Nguyệt tông lẩm bẩm rằng vật thật sự cần tìm nằm bên trong “cái hộp này”, còn những thứ trước đây chỉ là rác rưởi — gợi mở mục tiêu thật của Yểm Nguyệt tông tại cấm địa.","nguon":["@c0205"]},{"id":"chu-tuoc-hoan-nam-cung","name":"Chu tước hoàn (pháp bảo viên hoàn)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo","soHuu":["Nam Cung Uyển"],"trangThai":"dang-co","blurb":"Pháp bảo viên hoàn của Nam Cung sư tổ, có thể phun liệt hỏa, phóng lớn đỡ đòn và vây khốn yêu thú.","detail":"Pháp bảo viên hoàn hình dạng chu tước của Nam Cung sư tổ Yểm Nguyệt tông. Có thể phun liệt hỏa, phóng lớn để đỡ chất lỏng tím của Mặc Giao và vây khốn giữ chặt yêu thú. Là vũ khí duy nhất gây được chút thống khổ cho Mặc Giao sau khi nó tiến hóa bậc hai.","nguon":["@c0206"]},{"id":"kim-ti-phu","name":"Kim ti phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Trung cấp bậc trung","soHuu":["Nam Cung Uyển"],"trangThai":"da-dung","blurb":"Phù lục trung cấp bậc trung hóa thành kim quang rồi phân vô số sợi tơ vàng quấn chặt yêu thú một lúc.","detail":"Nam Cung sư tổ dùng Kim ti phù kích phát thành kim quang, phân ra vô số sợi tơ vàng quấn chặt Mặc Giao. Trong chốc lát đã trói được yêu thú, nhưng chỉ giữ được một lúc trước khi mất hiệu.","nguon":["@c0206"]},{"id":"tieu-ngu-hanh-phu","name":"Tiểu ngũ hành phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Trung cấp bậc thấp","soHuu":["Triệu sư muội (nữ tử áo trắng)"],"trangThai":"da-dung","blurb":"Phù lục trung cấp bậc thấp dán ở lối vào, phát động Tiểu ngũ hành tu di cấm pháp phong bế thông đạo.","detail":"Triệu sư muội dán Tiểu ngũ hành phù ở lối vào định hại Mặc Giao, nhưng phù phát động cấm pháp phong bế khiến hai bên thông đạo đá ép sát kín mít, vô tình nhốt Nam Cung sư tổ và Hàn Lập bên trong.","nguon":["@c0206"]},{"id":"hoa-linh-thach-nam-cung","name":"Hỏa linh thạch (màu đỏ)","cn":"","category":"linh-khi","categoryLabel":"Linh thạch","phamCap":"Không rõ","soHuu":["Nam Cung Uyển"],"trangThai":"da-dung","blurb":"Linh thạch màu đỏ Nam Cung sư tổ dùng để hấp nạp linh khí phục hồi pháp lực.","detail":"Hỏa linh thạch màu đỏ được Nam Cung sư tổ dùng để hấp nạp linh khí phục hồi pháp lực trong lúc chiến đấu với Mặc Giao.","nguon":["@c0206"]},{"id":"cac-phu-luc-trung-cap-nam-cung","name":"Thổ độn phù / Thủy lao phù / Hỏa điểu phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Trung cấp","soHuu":["Nam Cung Uyển"],"trangThai":"da-dung","blurb":"Các phù lục trung cấp khó gặp Nam Cung sư tổ xuất ra tạo hiệu ứng đặc biệt chuyển nguy thành an.","detail":"Nam Cung sư tổ liên tiếp xuất ra nhiều phù lục trung cấp khó gặp gồm Thổ độn phù, Thủy lao phù, Hỏa điểu phù... tạo các hiệu ứng đặc biệt để đối phó Mặc Giao, khiến Hàn Lập âm thầm kiêng dè.","nguon":["@c0206"]},{"id":"hop-vang-lo-lung-bach-ngoc","name":"Hộp vàng (lơ lửng trên bạch ngọc)","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Cái hộp vàng lơ lửng trên bạch ngọc mà Nam Cung sư tổ tiếc nuối, dự định lấy sau.","detail":"Một cái hộp vàng lơ lửng trên khối bạch ngọc trong khu chiến đấu. Nam Cung sư tổ tiếc nuối nhìn nó nhưng đành để lại, dự định sau này hãy tính; báo hiệu bảo vật quan trọng chưa thu được.","nguon":["@c0206"]},{"id":"binh-thuy-tinh-thu-nguyen-than","name":"Bình thủy tinh thu nguyên thần","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Cô gái (Sư tổ Yểm Nguyệt tông)"],"trangThai":"dang-co","blurb":"Bình nhỏ của cô gái bắn hắc khí kéo nguyên thần Mặc Giao ra và giam vào.","detail":"Cô gái lấy một bình thủy tinh nhỏ, niệm chú bắn ra mấy cổ hắc khí quấn thân Mặc Giao, kéo hình ảnh Mặc Giao nhỏ màu xanh (nguyên thần) thu vào bình. Cô mặt mày hớn hở cho thấy nguyên thần này rất giá trị.","nguon":["@c0207"]},{"id":"vien-chau-vang-co-gai","name":"Viên châu màu vàng (ám khí cô gái)","category":"khac","categoryLabel":"Ám khí","phamCap":"Không rõ","soHuu":["Cô gái (Sư tổ Yểm Nguyệt tông)"],"trangThai":"da-dung","blurb":"Viên châu vàng cô gái ném nổ thành khói vàng khống chế đầu Mặc Giao.","detail":"Cô gái ném một viên châu màu vàng, nổ tung thành khói vàng bao phủ đầu Mặc Giao, khiến nó ngừng phun dung dịch tím, tạo cơ hội cho kim chuyên hạ xuống.","nguon":["@c0207"]},{"id":"dung-dich-tim-mac-giao","name":"Dung dịch màu tím của Mặc Giao","category":"khac","categoryLabel":"Chất tiết yêu thú","phamCap":"Không rõ","soHuu":[],"trangThai":"da-dung","blurb":"Độc dịch màu tím Mặc Giao phun ra chặn kim chuyên, Hàn Lập kiêng kị.","detail":"Mặc Giao phun dung dịch màu tím chặn kim quang chuyên khiến nó không hạ xuống được; đây là độc dịch Hàn Lập kiêng kị.","nguon":["@c0207"]},{"id":"vien-cau-do-nghi-giao-dan","name":"Viên cầu màu đỏ (nghi giao đan)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":[],"trangThai":"hong","blurb":"Cầu đỏ mềm nhũn lớn bằng nắm tay moi từ bụng Mặc Giao, tự nổ phun sương hồng.","detail":"Hàn Lập moi từ bụng Mặc Giao ra viên cầu màu đỏ lớn bằng nắm tay. Cô gái nghi không phải nội đan thật vì Mặc Giao mới tiến hóa bậc hai và thuộc tính thủy thì nội đan phải màu lam. Khi cô vuốt nhẹ vài cái, viên cầu tự nổ tung phun ra sương khói màu hồng bao trùm cả hai.","nguon":["@c0207"]},{"id":"tai-lieu-than-mac-giao","name":"Tài liệu thân Mặc Giao","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cao cấp","soHuu":[],"trangThai":"dang-co","blurb":"Toàn thân Mặc Giao là tài liệu trân quý: da, sừng-móng, đan dịch.","detail":"Cô gái giải thích Mặc Giao tuy mới tiến hóa bậc hai nhưng toàn thân là tài liệu quý: da có thể luyện hộ giáp, sừng-móng luyện đỉnh cấp pháp khí, đan dịch luyện đan dược. Đáng tiếc chưa tiến hóa bậc ba nên không có nội giao đan.","nguon":["@c0207"]},{"id":"tui-dam-nang-thoi-tinh-mac-giao","name":"Túi dâm nang (thôi tình khí của Mặc Giao)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Mặc Giao"],"trangThai":"da-dung","blurb":"Túi chứa thôi tình vụ khí của Mặc Giao, chạm vào lập tức nổ tung.","detail":"Túi dâm nang của Mặc Giao, con súc sinh này thực ra là Hùng Giao hiếm thấy. Túi chứa thôi tình vụ khí, giống cái tiếp xúc sẽ lập tức nổ tung; thành phần mê dược trong đó rất ít, gây hôn mê cỡ năm sáu canh giờ. Chính là viên cầu khiến Hàn Lập và nữ tử hợp hoan; nữ tử sơ sẩy chạm phải nên nổ tung.","nguon":["@c0208"]},{"id":"hop-vang-bach-ngoc-dinh","name":"Hộp vàng (bạch ngọc đình)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Nữ tử tuyệt sắc (nữ tu Kết đan kỳ)"],"trangThai":"dang-co","blurb":"Hộp vàng đặt phía trước bên bạch ngọc đình, nữ tử thu vào túi trữ vật.","detail":"Hộp vàng đặt phía trước bên bạch ngọc đình. Nữ tử đòi lấy, Hàn Lập không dám tranh; nàng thu hộp vàng vào túi trữ vật thuận lợi. Công dụng chưa rõ.","nguon":["@c0208"]},{"id":"tui-tru-vat-de-tu-linh-thu-son","name":"Túi trữ vật (của đệ tử Linh thú sơn)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Túi trữ vật Hàn Lập đoạt được sau khi giết một đệ tử Linh thú sơn không đầu.","detail":"Sau khi giết một đệ tử Linh thú sơn ngoài cấm địa, Hàn Lập có thêm một túi trữ vật trong tay; hắn liếc qua rồi lắc đầu.","nguon":["@c0209"]},{"id":"truc-co-dan","name":"Trúc cơ đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Đan dược liên quan việc phân phối cho các phái sau cuộc thí luyện, khiến các đội trưởng Trúc cơ kỳ khẩn trương.","detail":"Việc phân phối trúc cơ đan là điểm mấu chốt của cuộc đánh cuộc giữa các phái; hơn mười đội trưởng Trúc cơ kỳ khẩn trương vì liên quan quyền lợi này.","nguon":["@c0209"]},{"id":"huyet-lan-tram-nam","name":"Huyết lan trăm năm","category":"dan-duoc","categoryLabel":"Đan dược / Linh dược","phamCap":"Linh dược trăm năm","soHuu":[],"trangThai":"dang-co","blurb":"Loại linh dược trưởng thành trăm năm, đạo sĩ Thanh Hư môn ra ba gốc trong đổ cục.","detail":"Linh dược trưởng thành khoảng trăm năm, được vị trung niên đạo sĩ Thanh Hư môn bày ra ba gốc trong cuộc đổ cục hái thuốc ở cấm địa.","nguon":["@c0210"]},{"id":"thien-linh-qua-linh-duoc","name":"Thiên linh quả (300 năm)","category":"dan-duoc","categoryLabel":"Đan dược / Linh dược","phamCap":"Linh dược ba trăm năm","soHuu":[],"trangThai":"dang-co","blurb":"Quả linh dược trưởng thành ba trăm năm, ra hai quả trong đổ cục.","detail":"Linh dược trưởng thành khoảng ba trăm năm, đạo sĩ Thanh Hư môn bày ra hai quả trong cuộc đổ cục.","nguon":["@c0210"]},{"id":"ngoc-tuy-chi","name":"Ngọc tủy chi","category":"dan-duoc","categoryLabel":"Đan dược / Linh dược","phamCap":"Linh dược bốn trăm năm","soHuu":[],"trangThai":"dang-co","blurb":"Loại linh dược trưởng thành bốn trăm năm, ra ba gốc trong đổ cục.","detail":"Linh dược trưởng thành khoảng bốn trăm năm, đạo sĩ Thanh Hư môn bày ra ba gốc trong cuộc đổ cục hái thuốc ở cấm địa.","nguon":["@c0210"]},{"id":"linh-thu-ngui-mui-do-cuc","name":"Linh thú ngửi mùi","category":"khac","categoryLabel":"Kỳ thú","phamCap":"Linh thú kiểm tra","soHuu":[],"trangThai":"dang-co","blurb":"Kỳ thú mỗi phái dẫn theo, trong phạm vi ba trượng ngửi ra bất kỳ linh dược trên trăm năm kể cả trong túi trữ vật.","detail":"Mỗi phái dẫn theo một hai con linh thú này để kiểm tra đệ tử ra khỏi cấm địa; trong phạm vi ba trượng có thể ngửi ra bất kỳ linh dược trên trăm năm dù được cất giấu trong túi trữ vật, khiến đệ tử không thể giấu thu hoạch.","nguon":["@c0210"]},{"id":"thiet-tinh","name":"Thiết tinh","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Lý Sư Tổ"],"trangThai":"dang-co","blurb":"Vật liệu quý mà Lý sư tổ hứa đưa hai khối cho Khung lão quái khi thua cuộc.","detail":"Vật đặt cược khi Lý sư tổ thua cược với Khung lão quái. Lý sư tổ chủ động đáp ứng trong vòng hai mươi năm sẽ cho người đem hai khối thiết tinh tới.","nguon":["@c0211"]},{"id":"ngan-kiem","name":"Ngân kiếm","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"khong-ro","blurb":"Thanh kiếm bạc của đệ tử Cự kiếm môn chân trần trong câu chuyện Hàn Lập bịa ra.","detail":"Xuất hiện trong câu chuyện trai cò tương tranh ngư ông đắc lợi mà Hàn Lập bịa để giải thích việc tìm được linh dược: một đệ tử Cự kiếm môn chân trần cầm ngân kiếm tranh đấu với người mặt đầy sẹo của Thiên khuyết bảo.","nguon":["@c0211"]},{"id":"bich-quang-dao","name":"Bích quang đao","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thanh trường đao đỉnh cấp linh quang lấp lóe, Lý Hóa Nguyên tặng Hàn Lập làm lễ gặp mặt khi thu ký danh đệ tử.","detail":"Pháp khí trường đao chất lượng cao, linh quang lấp lóe, được Lý Hóa Nguyên trao cho Hàn Lập như lễ gặp mặt trong nghi thức bái ký danh sư phụ, xem như minh chứng cho danh phận mới của hắn trong Hoàng phong cốc.","nguon":["@c0212"]},{"id":"khoi-loi-cung-thu","name":"Khôi lỗi cung thủ","aliases":["con rối cung thủ"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng phẩm pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Con rối gỗ điêu khắc sống động, mặc thiết giáp cầm trường cung đồng phát ngân quang; cần bí thuật phân thần mới khu sử.","detail":"Con rối bằng gỗ điêu khắc sống động, khoác thiết giáp thiết khôi, tay cầm trường cung đồng phát ánh ngân quang — thuộc thượng phẩm pháp khí. Muốn khu sử phải dùng bí thuật phân thân, rót một tia thần thức vào rối, nên chỉ tu sĩ Trúc cơ kỳ trở lên mới dùng được; Hàn Lập lúc này chưa thử dùng.","nguon":["@c0213"]},{"id":"to-giay-mau-bac","name":"Tờ giấy màu bạc","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Chiến lợi phẩm từ đại hán Cự kiếm môn; mặt lồi lõm nhiều hoa văn kỳ lạ thần bí, chưa giải được.","detail":"Vật lấy được từ đại hán chân trần của Cự kiếm môn trong cấm địa. Bề mặt lồi lõm với nhiều hoa văn kỳ lạ thần bí; Hàn Lập cân nhắc nửa ngày không hiểu công dụng, đành tạm cất và vừa nghiên cứu vừa chờ dịp giải mã.","nguon":["@c0213"]},{"id":"ngan-kiem-phe-vat","name":"Ngân kiếm phế vật","category":"phap-bao","categoryLabel":"Pháp khí (hỏng)","phamCap":"Phế vật","soHuu":["Hàn Lập"],"trangThai":"hong","blurb":"Một thanh ngân kiếm phế vật trong số chiến lợi phẩm thu được ở cấm địa.","detail":"Thanh ngân kiếm đã hỏng, nằm trong số thu hoạch của Hàn Lập từ cấm địa cùng linh thạch và tài liệu các loại.","nguon":["@c0213"]},{"id":"chuong-linh-phap-khi","name":"Chuông linh","aliases":["pháp khí linh đang"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp khí phát tiếng chuông; Hàn Lập dùng để khua tỉnh đại hán ngốc nghếch ở Nhạc lộc điện.","detail":"Một kiện pháp khí dạng chuông linh của Hàn Lập, được hắn dùng để khua đánh thức đại hán đang ngủ gật trong thông đạo Nhạc lộc điện.","nguon":["@c0213"]},{"id":"truc-co-dan-thanh-pham","name":"Trúc cơ đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Đan dược mục tiêu Hàn Lập chuẩn bị nhiều năm để luyện chế.","detail":"Đan dược Hàn Lập dồn công chuẩn bị mấy năm để tự luyện chế. Hắn tự nhận là tay mơ nên tính mỗi lần chỉ luyện một viên, chuẩn bị linh dược đủ luyện cả trăm lần để tích lũy kinh nghiệm, lường trước sẽ thất bại nhiều.","nguon":["@c0214"]},{"id":"lenh-tien-mau-tim","name":"Lệnh tiễn màu tím","cn":"","category":"khac","categoryLabel":"Lệnh phù","phamCap":"Không rõ","soHuu":["Đại hán ngốc nghếch (dẫn đường Địa Hỏa Chi Ốc)"],"trangThai":"dang-co","blurb":"Lệnh phù dùng mở cửa vào khu ổ thạch đạo của Địa Hỏa Chi Ốc.","detail":"Vật đại hán dùng bắn tia sáng vào cửa đá nhiều màu để kích hoạt, mở ra thông đạo ổ thạch đen ngòm cao hơn trượng dẫn vào Địa Hỏa Chi Ốc.","nguon":["@c0214"]},{"id":"ngoc-bai-mau-trang-gian-19","name":"Ngọc bài màu trắng (gian mười chín)","cn":"","category":"khac","categoryLabel":"Lệnh bài","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Chìa mở và phong bế cửa phòng luyện đan gian mười chín.","detail":"Ngọc bài trắng dùng mở và phong bế cửa đá trắng của phòng luyện đan gian mười chín; đại hán giao Hàn Lập tự giữ. Khi cửa đóng, phòng đoạn tuyệt liên hệ với ngoại giới trừ khi vài tu sĩ Kết đan kỳ hợp lực mới vào được.","nguon":["@c0214"]},{"id":"ho-lo-chua-hoa-tinh","name":"Hồ lô chứa hỏa tinh","cn":"","category":"khac","categoryLabel":"Vật phụ trợ luyện đan","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Hồ lô cỡ nắm tay chứa hỏa tinh, treo trên vách phòng luyện đan.","detail":"Các hồ lô cỡ nắm tay treo trên vách gian mười chín, chứa hỏa tinh dùng gia tăng uy lực địa hỏa khi nhiệt độ chưa đủ, nhưng hiệu lực chỉ kéo dài trong thời gian ngắn.","nguon":["@c0214"]},{"id":"linh-thach-bac-trung-hoa","name":"Linh thạch bậc trung (thuộc tính hỏa)","cn":"","category":"khac","categoryLabel":"Linh thạch","phamCap":"Bậc trung","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Linh thạch hỏa thuộc tính bậc trung, hấp nạp linh khí nhanh hơn nhiều linh thạch bậc thấp.","detail":"Khối linh thạch hỏa thuộc tính bậc trung Hàn Lập đưa cho đại hán để nhờ an bài phòng luyện đan. Theo quy ước một trăm linh thạch bậc thấp mới đổi được một khối bậc trung, nhưng hiếm ai chịu đổi vì bậc trung hấp nạp linh khí nhanh hơn nhiều.","nguon":["@c0214","@c0229"]},{"id":"ich-coc-dan","name":"Ích cốc đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Đan dược chống đói, ăn vào duy trì được khoảng một tháng không cần tiến thực.","detail":"Đan chống đói mà Hàn Lập đổi được một bình từ lão nhân nơi phòng địa hỏa, mượn cớ ra ngoài thu thập thảo dược trăm năm. Nhờ Ích cốc đan hắn duy trì thêm được một tháng để tiếp tục luyện chế Trúc cơ đan không gián đoạn.","nguon":["@c0215"]},{"id":"phe-dan-lam-nhat","name":"Phế đan (vụn màu lam nhạt)","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Vụn đan màu lam nhạt còn sót lại từ những lần luyện Trúc cơ đan chưa ngưng thành công.","detail":"Trong những lần luyện đan thất bại, đỉnh còn lại vô số vụn bể nát màu lam nhạt là phế đan chưa ngưng đan. Hàn Lập không vứt bỏ mà cẩn thận thu vào hộp ngọc, dự phòng về sau còn có thể có công dụng khác.","nguon":["@c0215"]},{"id":"phap-khi-han-lap-gia-ngu","name":"Pháp khí (Hàn Lập giá ngự)","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp khí bay Hàn Lập cưỡi khi rời Nhạc Lộc điện.","detail":"Pháp khí Hàn Lập giá ngự bay trên trời khi rời Nhạc Lộc điện sau khi trùng quan thành công vào Trúc cơ kỳ.","nguon":["@c0216"]},{"id":"me-tung-ky","name":"Mê tung kỳ","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lá cờ nhỏ cỡ bàn tay vẽ năm đỉnh núi bị sương mù che phủ, dùng để bày Mê tung pháp trận khai mở động phủ.","detail":"Trận kỳ nhỏ cỡ bàn tay, trên vẽ năm đỉnh núi bị sương mù che phủ, tỏa linh khí quỷ dị cổ quái. Chung Linh Đạo giao cho Hàn Lập cùng ngọc giản hướng dẫn để bày Mê tung pháp trận bảo vệ động phủ mới lập.","nguon":["@c0219"]},{"id":"ngoc-diep-trang-danh-sach","name":"Ngọc điệp trắng (danh sách động phủ)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Chung Linh Đạo"],"trangThai":"dang-co","blurb":"Ngọc điệp trắng ghi danh sách đệ tử; Chung Linh Đạo dùng bút cán vàng điền tên Hàn Lập để hắn có động phủ danh chính ngôn thuận.","detail":"Danh sách đệ tử được lưu trên ngọc điệp trắng. Chung Linh Đạo dùng bút cán vàng điền tên Hàn Lập vào phía dưới cùng để hắn được cấp động phủ một cách danh chính ngôn thuận.","nguon":["@c0219"]},{"id":"ngoc-gian-huong-dan-tran","name":"Ngọc giản hướng dẫn trận pháp","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản chứa thủ pháp bày và thao túng trận, điều chú ý sau Trúc Cơ, và tiến cử loài Song đồng thử.","detail":"Ngọc giản Chung Linh Đạo trao cho Hàn Lập, bên trong ghi thủ pháp bày và thao túng trận pháp, các điều cần chú ý sau khi Trúc Cơ, cùng tiến cử loài yêu thú Song đồng thử — thứ khiến Hàn Lập đổi hướng đến Kỳ lân các.","nguon":["@c0219"]},{"id":"qua-tho-le","name":"Quả thổ lê","cn":"","category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Loại quả vàng Song đồng thử thích ăn nhất, đựng trong túi trắng.","detail":"Quả thổ lê là loại quả màu vàng mà Song đồng thử thích ăn nhất, được nữ đệ tử Kỳ lân các đựng trong túi trắng giao cho Hàn Lập khi cho thuê con thú. Hàn Lập dùng thổ lê để dụ và điều khiển con thú lần theo tìm hang.","nguon":["@c0220"]},{"id":"linh-nhan-chi-vat","name":"Linh nhãn chi vật","aliases":["Linh nhãn chi tuyền","Linh nhãn chi thạch","Linh nhãn chi thụ"],"category":"khac","categoryLabel":"Bảo vật linh khí","phamCap":"Bảo vật quý (chia theo cấp)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bảo vật quý sản sinh nơi linh khí nồng đậm, khiến các môn phái tranh đoạt điên cuồng; gồm nhiều loại như thạch, thụ, tuyền.","detail":"Linh nhãn chi vật là bảo vật quý sinh ra ở nơi linh khí nồng đậm, mỗi lần xuất hiện đều gây gió tanh mưa máu vì các môn phái tranh đoạt điên cuồng. Chúng gồm nhiều loại: linh nhãn chi thạch, linh nhãn chi thụ, linh nhãn chi tuyền. Tại Việt quốc chúng sớm đã rơi vào tay thất đại phái; Hoàng Phong Cốc từng có hai khối linh nhãn chi thạch, ba khối linh nhãn chi thụ, bảy linh nhãn chi tuyền và hơn mười linh nhãn chi vật, bị các tu sĩ Kết đan kỳ và lão tổ Nguyên Anh kỳ chia hết. Hàn Lập tình cờ tìm được một linh nhãn chi tuyền nhất cấp nhỏ đến đáng thương ở phụ cận đỉnh núi và dùng nó làm động phủ, giúp tăng tốc tu luyện hơn nửa thành.","nguon":["@c0221"]},{"id":"tran-ky-tran-ban","name":"Trận kỳ / trận bàn","category":"phap-bao","categoryLabel":"Pháp khí bố trận","phamCap":"Pháp khí bố trận","soHuu":["Thiên Tinh Tông"],"trangThai":"dang-co","blurb":"Pháp khí dựa vào để bố trí trận pháp mà không cần tu luyện trận đạo, chỉ cần linh thạch là mua được.","detail":"Trận kỳ và trận bàn là loại pháp khí cho phép tu sĩ bố trí trận pháp mà không cần dành hàng chục năm tu luyện trận đạo. Dù không tạo được cấm pháp đại trận, chúng đủ dùng cho các trận phòng thủ tầm thường, lấy số lượng bù chất lượng. Thiên Tinh Tông của Nguyên Vũ Quốc nổi danh nhờ luyện chế và bày bán loại pháp khí này, chỉ cần có linh thạch là có thể mua được. Đây là mục tiêu chính khiến Hàn Lập lặn lội tới phường thị của tông môn.","nguon":["@c0221"]},{"id":"dinh-cap-phap-khi-tinh-pham","name":"Đỉnh cấp pháp khí (tinh phẩm)","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Đỉnh cấp","soHuu":[],"trangThai":"dang-co","blurb":"Loại pháp khí cao cấp, giá động đến vài trăm linh thạch bậc thấp; tinh phẩm là mức cao nhất trong đỉnh cấp.","detail":"Pháp khí đỉnh cấp có giá trị rất cao, chỉ động đến cũng phải vài trăm linh thạch bậc thấp, người tu tiên bình thường gom cả đời chưa chắc mua nổi một kiện. Luyện chế đỉnh cấp pháp khí cần hỏa lực mạnh như tiên thiên chân hỏa hoặc địa hỏa, tương tự khi luyện Trúc Cơ đan. Hàn Lập tới gian hàng luyện khí đòi xem tinh phẩm của đỉnh cấp pháp khí nhưng tiệm chỉ có loại bình thường, nên hắn giao tài liệu để Từ lão giả luyện chế.","nguon":["@c0222"]},{"id":"hoa-van-kiem","name":"Hỏa Vân Kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":[],"trangThai":"dang-co","blurb":"Kiện pháp khí là vật phẩm đầu tiên do bản điếm chủ trì đưa ra đấu giá tại cạnh mại hội của bí điếm.","detail":"Hỏa Vân Kiếm được một trung niên nam tử cao gầy vẻ mặt khôn khéo bước ra giới thiệu, mở màn chuỗi đấu giá của cạnh mại hội ngầm mà Hàn Lập tham dự.","nguon":["@c0223"]},{"id":"khoi-loi-co-quan-thu","name":"Khôi lỗi cơ quan thú","cn":"","aliases":["đôi khôi lỗi thú","khôi lỗi thú"],"category":"phap-bao","categoryLabel":"Pháp bảo (thượng cấp)","phamCap":"Thượng cấp pháp khí (khôi lỗi thú cấp hai)","soHuu":[],"trangThai":"dang-co","blurb":"Một cặp khôi lỗi màu đen sáng bóng, kích cỡ bằng nắm tay, ngoại hình hao hao sư tử-hổ; thực lực ngang tu sĩ Luyện Khí kỳ tầng chín.","detail":"Cặp khôi lỗi cơ quan thú là thượng cấp pháp khí do khôi lỗi cơ quan thuật chế thành, xếp vào khôi lỗi thú cấp hai theo phân cấp chính thức. Thân màu đen sáng bóng, kích cỡ bằng nắm tay, hình dáng hao hao giữa sư tử và hổ nhưng không rõ nguyên hình quái thú. Thực lực ngang tu sĩ Luyện Khí kỳ tầng chín, tuyệt đối trung thành và hung dữ không sợ chết. Được rao bán tại phiên đấu giá bí điếm, bị hai quái nhân đẩy giá bất thường tới trên chín trăm linh thạch kèm bảo vật.","nguon":["@c0224"]},{"id":"hong-la-thien-lo","name":"Hồng La Thiên lô","cn":"","aliases":[],"category":"khac","categoryLabel":"Đan lô","phamCap":"Đan lô đỉnh cấp","soHuu":["Nữ tu sĩ Trúc Cơ kỳ (mua Hồng La Thiên lô)"],"trangThai":"dang-co","blurb":"Đan lô đỉnh cấp màu hỏa hồng được luyện khí sư yêu quí, từng truyền qua nhiều luyện khí đại sư.","detail":"Hồng La Thiên lô là đan lô đỉnh cấp màu hỏa hồng, được giới luyện khí sư trân quí nhất, từng qua tay nhiều luyện khí đại sư và luyện chế ra hàng loạt tinh phẩm pháp khí như Huyễn Âm kiếm, Thanh Giao kỳ, Hắc Viêm châu. Nghe nói lô này gia tăng thành công suất luyện chế. Tại phiên đấu giá bí điếm được bán với tám trăm năm mươi mốt linh thạch. Chi tiết Thanh Giao kỳ trong tay Hàn Lập cũng xuất từ đan lô này khiến hắn kinh ngạc.","nguon":["@c0224"]},{"id":"huyen-am-kiem","name":"Huyễn Âm kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí (tinh phẩm)","phamCap":"Tinh phẩm pháp khí","soHuu":[],"trangThai":"khong-ro","blurb":"Tinh phẩm pháp khí được nêu là từng luyện chế bằng Hồng La Thiên lô.","detail":"Huyễn Âm kiếm được nhắc tên như một trong các tinh phẩm pháp khí từng ra đời từ đan lô Hồng La Thiên lô, dùng để minh chứng đẳng cấp và giá trị của đan lô này trong phiên đấu giá bí điếm.","nguon":["@c0224"]},{"id":"hac-viem-chau","name":"Hắc Viêm châu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí (tinh phẩm)","phamCap":"Tinh phẩm pháp khí","soHuu":[],"trangThai":"khong-ro","blurb":"Tinh phẩm pháp khí được nêu là từng luyện chế bằng Hồng La Thiên lô.","detail":"Hắc Viêm châu được nhắc tên như một trong các tinh phẩm pháp khí từng luyện chế bằng đan lô Hồng La Thiên lô, dùng làm dẫn chứng cho giá trị đan lô trong phiên đấu giá bí điếm.","nguon":["@c0224"]},{"id":"do-vat-trao-doi-nguoi-khoi-ngo","name":"Đồ vật trao đổi của người khôi ngô","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm trao đổi","phamCap":"Trị giá mấy ngàn linh thạch","soHuu":["Người khôi ngô đội mũ xanh biếc"],"trangThai":"dang-co","blurb":"Món đồ được nói trị giá mấy ngàn linh thạch mà người khôi ngô dùng thêm vào giá để đổi cặp khôi lỗi thú.","detail":"Trong lúc quýnh lên giành cặp khôi lỗi cơ quan thú, người khôi ngô đội mũ xanh biếc lôi ra một món đồ được nói trị giá mấy ngàn linh thạch, cộng thêm chín trăm linh thạch để ép bí điếm giao khôi lỗi thú ngay. Bản chất và công năng cụ thể của món đồ chưa được tiết lộ.","nguon":["@c0224"]},{"id":"hoang-tinh-chi-ngan-nam","name":"Hoàng Tinh chi ngàn năm","cn":"","category":"nguyen-lieu","categoryLabel":"Linh dược","phamCap":"Linh dược đỉnh cấp","soHuu":["Hàn Lập","Vạn Bảo lâu"],"trangThai":"dang-co","blurb":"Gốc linh dược đỉnh cấp ngàn năm, gần trăm năm mới hiện thế vài lần, dùng luyện linh đan để đột phá cảnh giới. Một trong hai gốc do Hàn Lập tự nuôi dưỡng, từng bán cho Vạn Bảo lâu.","detail":"Gốc dược thảo ngàn năm quý hiếm, gần trăm năm mới hiện thế vài lần, được dùng để luyện linh đan phục vụ đột phá cảnh giới. Đựng trong hộp ngọc xanh biếc, khi mở ra tỏa dược hương nồng đậm tràn ngập đại sảnh. Tại buổi đấu giá bí điếm, nam tử cao gầy đưa ra làm vật cuối cùng với giá khởi điểm năm trăm linh thạch, các tu sĩ tranh nhau hô giá từ một ngàn vượt hai ngàn linh thạch. Hàn Lập nhận ra đây chính là một trong hai gốc do chính mình nuôi dưỡng và từng bán cho Vạn Bảo lâu.","nguon":["@c0225"]},{"id":"hop-ngoc-xanh-biec-dung-linh-duoc","name":"Hộp ngọc xanh biếc","cn":"","category":"khac","categoryLabel":"Hộp đựng","phamCap":"Không rõ","soHuu":["Nam tử cao gầy (chủ trì bí điếm)"],"trangThai":"dang-co","blurb":"Hộp ngọc màu xanh biếc dùng đựng gốc Hoàng Tinh chi ngàn năm tại buổi đấu giá bí điếm.","detail":"Hộp bằng ngọc xanh biếc có vỏ bọc rút ra được, dùng để đựng và bảo quản gốc Hoàng Tinh chi ngàn năm. Khi mở ra, dược hương của linh dược tràn ngập đại sảnh đấu giá.","nguon":["@c0225"]},{"id":"bo-bo-tran-phap-khi-dien-dao-ngu-hanh","name":"Bộ bố trận pháp khí Điên Đảo Ngũ Hành Trận (tàn phẩm)","category":"khac","categoryLabel":"Khí cụ trận pháp","phamCap":"Tàn phẩm (một phần mười uy lực)","soHuu":["Tề Vân Tiêu"],"trangThai":"dang-co","blurb":"Bộ khí cụ pháp khí hóa của kỳ trận Điên Đảo Ngũ Hành Trận, hiện chưa thành công, chỉ phát huy một phần mười uy lực nguyên trận.","detail":"Là mục tiêu Hàn Lập muốn đổi lấy bằng thiên niên linh dược, dù chỉ còn một phần mười công hiệu vẫn đủ dùng cho động phủ đơn giản. Thanh niên hứa vài năm sẽ nâng lên tối thiểu nửa uy lực.","nguon":["@c0226"]},{"id":"thien-nien-tu-que-hoa","name":"Thiên niên Tử Quế Hoa","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Thiên niên linh dược","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Dược thảo trên nghìn năm giá trị không thấp hơn Hoàng Tinh Chi.","detail":"Hàn Lập lấy ra làm vật mặc cả với thanh niên trận pháp sư, không mở hộp ngay mà đòi đối phương nói rõ dùng vật gì trao đổi.","nguon":["@c0226"]},{"id":"huyen-nguyet-thach","name":"Huyễn Nguyệt Thạch","category":"nguyen-lieu","categoryLabel":"Khoáng thạch / linh vật","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Viên đá được tu sĩ Trúc Cơ kỳ dùng kèm hai ngàn linh thạch để đấu được thiên niên dược thảo.","detail":"Xuất hiện trong đấu giá mật điếm như vật thanh toán bổ sung cho thiên niên linh thảo.","nguon":["@c0226"]},{"id":"ngoc-gian-phuong-phap-bo-tran-dien-dao","name":"Ngọc Giản (phương pháp bố trận Điên Đảo Ngũ Hành Trận)","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc Giản ghi phương pháp bố trí bộ pháp khí Điên Đảo Ngũ Hành Trận.","detail":"Ngọc Giản ghi lại phương pháp bố trí bộ bố trận pháp khí Điên Đảo Ngũ Hành Trận gồm trận bàn và trận kỳ, để đại trận phát sinh hiệu lực. Tề Vân Tiêu giao cho Hàn Lập cùng bộ pháp khí và quyển Vân Tiêu Tâm Thuật trong giao dịch đổi lấy thiên niên linh dược.","nguon":["@c0227"]},{"id":"thien-nien-linh-duoc-trong-hop","name":"Thiên niên linh dược (trong hộp)","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Linh dược ngàn năm trong hộp của Hàn Lập, dược hương đầy linh khí; dùng trao đổi lấy bộ pháp khí và Vân Tiêu Tâm Thuật.","detail":"Linh dược ngàn năm trong hộp của Hàn Lập, dược hương tỏa ra đầy linh khí. Hàn Lập mở hộp cho Tề Vân Tiêu ngửi nhưng giữ chặt không cho lấy, ám thị đòi giao hàng trước; cuối cùng dùng làm vật trao đổi lấy bộ bố trận pháp khí Điên Đảo Ngũ Hành Trận, Ngọc Giản và quyển Vân Tiêu Tâm Thuật.","nguon":["@c0227"]},{"id":"vo-cung-ngo-cong","name":"Vỏ cứng của ngô công","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Vỏ ngoài của yêu thú loại độc trùng thượng cấp bậc một, hiếm; là tài liệu luyện khí rất tốt.","detail":"Vỏ cứng ngoài của một yêu thú thuộc loại độc trùng thượng cấp bậc một, rất hiếm. Lão giả tóc bạc chủ tiệm Luyện khí nhận định là tài liệu luyện khí thượng cấp thích hợp làm hộ giáp, thuẫn bài, có thể luyện thành đỉnh cấp pháp khí; ngay khi chưa chế luyện đã có thể ngạnh tiếp một kích của đỉnh giai pháp khí. Hàn Lập lấy ra bán cho lão nhưng chặn lại vì còn tài liệu khác chưa lấy ra.","nguon":["@c0227"]},{"id":"than-phong-chau","name":"Thần Phong Châu","cn":"","aliases":["Thần Phong chu"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí phi hành cao cấp","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thuyền nhỏ màu trắng luyện từ vẩy và da Mặc Giao, biến lớn thành thuyền độc mộc chở mấy người, tốc độ cực nhanh nhưng không có năng lực phòng vệ.","detail":"Pháp khí phi hành do Từ lão luyện từ vẩy và da giao long Mặc Giao. Khi Hàn Lập dùng pháp quyết màu xanh, thuyền trắng biến thành thuyền độc mộc như thật chở được mấy người, đưa hắn lên không trung; tốc độ hiếm có, chỉ dùng nửa tốc độ cũng về động phủ trong một thời thần. Nhược điểm là không chở được nhiều người và không có năng lực phòng vệ. Hàn Lập rất hài lòng, thay thế pháp khí hình chiếc lá chậm chạp cũ, và đánh giá so với Thiên Nguyệt Thần Châu của Yểm Nguyện Tông.","nguon":["@c0228"]},{"id":"hai-vien-cau-xanh-do-may-che-giau","name":"Hai viên cầu xanh-đỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Cặp cầu xanh và đỏ của Hàn Lập, đập vào nhau tạo cụm mây xanh đỏ đường kính hơn mười trượng bao trùm và giấu kín thân ảnh.","detail":"Hai viên cầu — một xanh một đỏ — khi đập vào nhau đồng thời tuôn ra một cụm khói xanh đỏ đường kính hơn mười trượng, bao trùm và che giấu thân ảnh Hàn Lập khỏi tầm nhìn để hắn an toàn quan sát trận chiến dưới đất.","nguon":["@c0228"]},{"id":"tai-lieu-mac-giao","name":"Tài liệu Mặc Giao","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Nguyên liệu quý","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Da giao long, vẩy, sừng, răng nanh, nhãn châu, lợi trảo từ thân Mặc Giao — nguyên liệu quý dùng luyện chế pháp khí.","detail":"Bộ nguyên liệu luyện khí lấy từ thân con giao long Mặc Giao gồm da, vẩy, sừng, răng nanh, nhãn châu, lợi trảo. Vì giao long là thiên địa yêu thú đã biến mất từ lâu ở tu tiên giới nên tài liệu cực quý; Hàn Lập giao cho Từ lão luyện chế, trong đó vẩy và da dùng chế Thần Phong Châu.","nguon":["@c0228"]},{"id":"phap-khi-hinh-la-co-tron-chay","name":"Pháp khí hình lá cờ (tu sĩ bị vây)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Pháp khí hình lá cờ một tu sĩ Trúc Cơ dùng để thoát ly hộ trạo bay ra ngoài định trốn chạy khỏi vòng vây khôi lỗi.","detail":"Pháp khí phòng ngự hình lá cờ mà một vị tu sĩ trong nhóm bị vây dùng để tăng phòng hộ và thoát ly hộ trạo hợp lực bay ra ngoài trốn chạy; nhưng vừa ra khỏi liền bị siêu cấp quang trụ bắn trúng.","nguon":["@c0228"]},{"id":"dao-thuong-khoi-loi-can-chien","name":"Đao thương khôi lỗi cận chiến","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí cấp thấp","soHuu":[],"trangThai":"dang-co","blurb":"Binh khí sáng lòa trong tay khôi lỗi cận chiến mang trọng khải, xác thực là pháp khí cấp thấp.","detail":"Đao thương do đám khôi lỗi cận chiến (người máy mang trọng khải) cầm khi vây công nhóm Trúc Cơ tu sĩ; binh khí sáng lòa, được Hàn Lập nhận ra là pháp khí cấp thấp.","nguon":["@c0228"]},{"id":"thanh-hoa-chuong","name":"Thanh Hỏa Chướng","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Kỳ môn pháp khí","phamCap":"Đỉnh cấp pháp khí (đôi)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Đôi đỉnh cấp pháp khí kỳ môn của Hàn Lập, luyện từ mắt giao long, hóa thành sương mù xanh đỏ vừa che dấu thân ảnh vừa mang độc.","detail":"Hai đỉnh cấp pháp khí luyện chế từ mắt giao long, hóa thành sương mù xanh đỏ che dấu thân ảnh khiến người khác không nắm chắc vị trí. Được nhúng máu còn sót của Mạc Giao nên có thể khiến kẻ tiếp xúc chóng mặt nhức đầu, từ từ trúng độc mà không hay biết. Hàn Lập dùng nó ẩn mình trên không, đưa toàn bộ vân chướng xuyên nhập tầng mây xám để giấu thân triệt để.","nguon":["@c0229"]},{"id":"cu-ho-khoi-loi-ho-khong-lo","name":"Cự Hổ (khôi lỗi hổ khổng lồ)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Khôi lỗi cơ quan thú","phamCap":"Không rõ","soHuu":["Nam tử khôi vũ (Thiên Trúc Giáo)"],"trangThai":"dang-co","blurb":"Khôi lỗi hổ khổng lồ cao năm sáu trượng của nam tử khôi vũ, phun quang trụ bạch sắc siêu cấp uy lực cực lớn từ miệng.","detail":"Khôi lỗi hổ cao đến năm sáu trượng, phun quang trụ bạch sắc siêu cấp uy lực cực lớn từ hàm dưới sau khi ngưng tụ bạch quang. Trên đầu hổ có cửa bí mật để nạp linh thạch bậc trung thuộc tính hỏa làm nhiên liệu; một kích toàn lực tiêu hao trọn nguyên một khối linh thạch bậc trung. Nam tử khôi vũ ngồi trên đầu hổ điều khiển, dùng nó bắn chết đám tu sĩ Nguyên Vũ Quốc.","nguon":["@c0229"]},{"id":"khoi-loi-bo-ha-cu-ho","name":"Khôi lỗi bộ hạ (đám khôi lỗi máy)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Khôi lỗi máy","phamCap":"Không rõ","soHuu":["Nam tử khôi vũ (Thiên Trúc Giáo)"],"trangThai":"dang-co","blurb":"Các khôi lỗi máy công kích hộ trạo đám tu sĩ, rút lui khi Cự Hổ khai hỏa.","detail":"Đám khôi lỗi máy do nam tử khôi vũ điều khiển, ban đầu công kích hộ trạo đám tu sĩ Nguyên Vũ Quốc; khi Cự Hổ chuẩn bị phun quang trụ thì được lệnh dừng tay rút lui.","nguon":["@c0229"]},{"id":"hac-ti-co","name":"Hắc Ti Cổ","category":"khac","categoryLabel":"Độc / cổ trùng","phamCap":"Kỳ độc","soHuu":["Hoàng Long"],"trangThai":"da-dung","blurb":"Kỳ độc Hoàng Long phải ngàn cay vạn đắng mới cầu được từ Cổ Độc Tông. Được gieo qua hai lỗ máu trên cổ tay Lâm sư huynh, khó thanh trừ, thiết kế để trói buộc đối phương chờ phát tác.","detail":"Hắc Ti Cổ là kỳ độc Hoàng Long cầu được từ Cổ Độc Tông với ngàn cay vạn đắng. Hắn cấy nó vào Lâm sư huynh qua cái bắt tay giả vui mừng, để lại hai lỗ máu sâu cỡ cây đũa trên cổ tay đối phương. Loại độc này khó thanh trừ, được dùng làm mắt xích then chốt trong bẫy của Kim Giáo Chủ nhằm trói buộc Lâm sư huynh chờ độc phát tác. Lâm sư huynh kịp bức máu độc rồi uống bột phấn vàng trong bình ngọc xanh lục để giải.","nguon":["@c0230"]},{"id":"binh-ngoc-xanh-luc-bot-phan-vang","name":"Bình ngọc màu xanh lục chứa bột phấn vàng","category":"dan-duoc","categoryLabel":"Đan dược / giải độc","phamCap":"Không rõ","soHuu":["Lâm sư huynh"],"trangThai":"da-dung","blurb":"Bình ngọc màu xanh lục đựng bột phấn vàng dùng để giải độc. Lâm sư huynh đổ toàn bộ bột vào miệng để giải Hắc Ti Cổ.","detail":"Bình ngọc màu xanh lục chứa bột phấn vàng, là vật giải độc của Lâm sư huynh. Khi trúng Hắc Ti Cổ, hắn bức máu độc ra rồi đổ toàn bộ bột phấn vàng trong bình vào miệng để hóa giải kỳ độc từ Cổ Độc Tông.","nguon":["@c0230"]},{"id":"chiec-binh-nho-than-bi","name":"Chiếc bình nhỏ thần bí","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dị bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bảo vật bí ẩn của Hàn Lập có khả năng thúc linh dược trưởng thành nhanh, giúp luyện đan bù đắp tư chất kém.","detail":"Được Hàn Lập xác định là lợi thế then chốt trên con đường tiến lên Kết Đan: nhờ khả năng thúc linh dược trưởng thành, hắn có thể luyện đan để bù cho tư chất tu luyện kém của mình. Hắn coi đây là chỗ dựa để mưu tính đường tu luyện lâu dài.","nguon":["@c0231"]},{"id":"truc-bai-xanh-biec","name":"Trúc bài xanh biếc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hoàng Long"],"trangThai":"dang-co","blurb":"Kiện trúc bài lớn màu xanh biếc nổi bồng bềnh trên không, chở nhóm sáu bảy người Thiên Trúc giáo tới tấn công động phủ Hàn Lập.","detail":"Pháp bảo bay của Thiên Trúc giáo: một trúc bài xanh biếc cỡ lớn lơ lửng giữa không trung, trên đó có Hoàng Long dẫn đầu cùng đôi nam nữ và bốn huynh đệ song sinh. Nó là bệ đứng cho nhóm công kích đại trận động phủ Hàn Lập.","nguon":["@c0231"]},{"id":"tui-tru-vat-lam-su-huynh","name":"Túi trữ vật (Lâm sư huynh)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Lâm sư huynh"],"trangThai":"dang-co","blurb":"Túi trữ vật trên áo xác Lâm sư huynh mà Hàn Lập lục tìm, kỳ vọng chứa khôi lỗi.","detail":"Khi lật thi thể Lâm sư huynh, Hàn Lập lục túi trữ vật trên áo hắn với hy vọng tìm được khôi lỗi. Chính lúc đó thần hồn Lâm sư huynh hóa đoàn sáng màu lục từ áo bay ra định đoạt xá.","nguon":["@c0231"]},{"id":"hai-goc-duoc-tai-sau-bay-tram-nam","name":"Hai gốc dược tài sáu bảy trăm năm","category":"nguyen-lieu","categoryLabel":"Linh dược / Dược thảo","phamCap":"Sáu bảy trăm năm","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hai gốc linh dược lâu năm Hàn Lập dùng làm mồi thu hút Lôi Vạn Hạc.","detail":"Hai gốc dược tài đã dùng khoảng sáu, bảy trăm năm, mua từ bên ngoài tốn không ít linh thạch, linh khí bức người. Hàn Lập lấy ra từ trữ tàng thất, nhờ Lôi Vạn Hạc xem giúp thật giả và tuổi linh dược, thực chất dùng làm mồi tạo quan hệ giao hảo với tu sĩ Kết Đan kỳ.","nguon":["@c0234"]},{"id":"phap-khi-hop-ngoc-dung-thuoc","name":"Pháp khí hộp ngọc (hộp đựng thuốc)","category":"phap-bao","categoryLabel":"Pháp khí cất chứa","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Pháp khí cất chứa linh dược, chỉ giữ dược lực tạm thời.","detail":"Dùng cất chứa linh dược nhưng chỉ giữ tạm thời; để thời gian dài thì dược lực từ từ tiêu tán, nên động phủ tu tiên thường bố trí trữ tàng thất riêng để giữ dược tính vĩnh viễn.","nguon":["@c0234"]},{"id":"ngoc-gian-cam-doan-than-thuc","name":"Ngọc giản (ghi phương pháp cấm đoạn thần thức)","category":"khac","categoryLabel":"Vật phẩm ghi chép","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản ghi rõ đặc điểm biến hóa cấm đoạn thần thức của trận pháp.","detail":"Ghi rõ biến hóa cấm đoạn thần thức của Điên Đảo Ngũ Hành trận cực đơn giản dễ dàng, luyện chế pháp khí thì uy lực giống hoàn toàn chính bản — công hiệu duy nhất có thể sánh với chính bản.","nguon":["@c0234"]},{"id":"tang-nguyen-dan","name":"Tăng Nguyên đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Loại đan dược Lôi Vạn Hạc muốn khai lô luyện chế để phụ trợ đột phá bình cảnh.","detail":"Đan dược mà Lôi Vạn Hạc dự tính luyện chế nhằm hỗ trợ vượt qua bình cảnh Kết Đan kỳ. Đòi hỏi chủ dược là linh dược đã ngoài năm trăm năm; nếu dùng linh thảo không đủ năm tuổi thì công hiệu suy giảm đáng kể. Đây là lý do lão thèm khát hai gốc linh thảo sáu-bảy trăm năm của Hàn Lập.","nguon":["@c0235","@c0236"]},{"id":"hai-goc-linh-thao-sau-bay-tram-nam","name":"Hai gốc linh thảo (sáu-bảy trăm năm)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hai gốc linh thảo trân phẩm của Hàn Lập, được phán đoán đủ sáu-bảy trăm năm.","detail":"Hai gốc dược tài quý mà Hàn Lập sở hữu; Lôi Vạn Hạc vừa nhìn đã đoán đủ sáu, bảy trăm năm tuổi, thuộc loại trân phẩm khó tìm. Là vật trục tâm điểm của cuộc mặc cả trong chương: Hàn Lập dùng chúng làm giá đổi lấy một phương pháp luyện đan thích hợp.","nguon":["@c0235"]},{"id":"linh-thao-ngan-nam-bi-diem","name":"Linh thảo ngàn năm (bí điếm)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"khac","blurb":"Gốc linh thảo ngàn năm Hàn Lập kể (nửa thật nửa giả) từng thấy ở bí điếm, dùng làm mồi kích Lôi Vạn Hạc.","detail":"Gốc linh thảo ngàn năm mà Hàn Lập kể mình từng thấy ở một bí điếm nhưng vô lực mua nổi, đành trơ mắt nhìn người khác mua đi. Câu chuyện nửa thật nửa giả này được Hàn Lập tung ra để kích động lòng tham và sự tiếc nuối của Lôi Vạn Hạc, dọn đường cho cuộc trao đổi.","nguon":["@c0235"]},{"id":"chu-linh-thao","name":"Chu Linh thảo","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Linh thảo","soHuu":["Hàn Lập","Lôi Vạn Hạc"],"trangThai":"dang-co","blurb":"Loại linh thảo Hàn Lập có hai cây, dùng làm vật trao đổi phương thuốc cổ với Lôi Vạn Hạc.","detail":"Hàn Lập sở hữu hai gốc Chu Linh thảo. Trong cuộc giao dịch với Lôi Vạn Hạc, hai bên chốt dùng một gốc Chu Linh thảo đổi một cách điều chế phương thuốc cổ. Lôi Vạn Hạc thu nhận linh thảo để về luyện chế Tăng Nguyên đan của mình.","nguon":["@c0236"]},{"id":"tu-linh-dan","name":"Tụ Linh đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Phương thuốc cổ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Một trong hai phương thuốc cổ Hàn Lập chọn được từ mục lục của Lôi Vạn Hạc.","detail":"Phương điều chế đan dược cổ mà Hàn Lập chọn từ ngọc giản mục lục phương thuốc do Lôi Vạn Hạc đưa. Cùng với Luyện Khí tán, đây là kết quả cuộc trao đổi đổi Chu Linh thảo lấy cách điều chế.","nguon":["@c0236"]},{"id":"luyen-khi-tan","name":"Luyện Khí tán","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Phương thuốc cổ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phương thuốc cổ thứ hai Hàn Lập chọn từ mục lục phương thuốc của Lôi Vạn Hạc.","detail":"Phương điều chế đan dược cổ Hàn Lập chọn từ ngọc giản mục lục do Lôi Vạn Hạc cung cấp, bên cạnh Tụ Linh đan. Lôi Vạn Hạc lôi ra ngọc giản riêng ghi phương này để giao cho Hàn Lập.","nguon":["@c0236"]},{"id":"ngoc-gian-muc-luc-phuong-thuoc","name":"Ngọc giản mục lục phương thuốc","category":"khac","categoryLabel":"Khác","phamCap":"Ngọc giản","soHuu":["Lôi Vạn Hạc"],"trangThai":"dang-co","blurb":"Ngọc giản Lôi Vạn Hạc đưa Hàn Lập, chứa danh sách phương thuốc kèm tính năng và nguyên liệu cần dùng.","detail":"Lôi Vạn Hạc đưa cho Hàn Lập một ngọc giản ghi mục lục các phương thuốc cổ của mình, kèm mô tả tính năng đan dược và nguyên liệu cần dùng. Nhờ đó Hàn Lập chọn được Tụ Linh đan và Luyện Khí tán, đồng thời thắc mắc lão hoàn thành mục lục này lúc nào.","nguon":["@c0236"]},{"id":"truyen-am-phu","name":"Truyền Âm phù","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Tờ phù dùng để truyền tin. Hàn Lập thấp giọng nói vào rồi ném đi, phù hóa thành đạo hỏa quang vọt vào màn nước báo tin đến động phủ.","detail":"Hàn Lập dùng khi tới trước động phủ Lý Hóa Nguyên: thấp giọng nói mấy câu vào tờ phù rồi ném ra, phù hóa thành một đạo hỏa quang vọt vào màn nước để báo tin. Sau một nén nhang thì Vu Khôn ra đón.","nguon":["@c0237"]},{"id":"linh-duoc-thien-dia","name":"Linh dược thiên địa","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Hàn Lập","Lý Hóa Nguyên"],"trangThai":"da-dung","blurb":"Số linh dược thiên địa Hàn Lập từng có, bị Lý Hóa Nguyên lấy đi một nửa lấy danh nghĩa thu đồ; phần còn lại được luyện đan cứu mạng phu nhân của lão.","detail":"Lý Hóa Nguyên thu Hàn Lập làm đồ đệ vì tham số linh dược thiên địa này, lấy đi một nửa (nếu không Hàn Lập đã nhận hai viên Trúc Cơ đan thay vì một). Về sau chính số linh dược đó được luyện đan trong mấy năm để cứu chữa phu nhân của lão bị tu luyện sai lầm suýt mất mạng.","nguon":["@c0238"]},{"id":"kho-cong-phap-tang-thu-that","name":"Kho công pháp Tàng thư thất","category":"khac","categoryLabel":"Kho công pháp","phamCap":"","soHuu":["Lý Hóa Nguyên"],"trangThai":"dang-co","blurb":"Năm sáu mươi kiện ngọc giản, sách, hộp nổi lơ lửng tản kỳ quang, là công pháp Lý Hóa Nguyên thu thập mấy trăm năm.","detail":"Bên trong Tàng thư thất có năm, sáu mươi kiện ngọc giản, sách, hộp và bộ sách nổi lơ lửng tản kỳ quang đủ màu, là công pháp Lý Hóa Nguyên thu thập trong mấy trăm năm. Mỗi món đều bị hạ cấm chế bảo vệ.","nguon":["@c0239"]},{"id":"quyen-sach-mau-bac","name":"Quyển sách màu bạc","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quyển sách Hàn Lập đang giữ, bề mặt có hoa văn cổ quái; khi bị nung, bề mặt tan chảy để lộ một lớp sách màu vàng bên trong không sợ lửa.","detail":"Quyển sách màu bạc Hàn Lập đang giữ, tên gọi trước đây là Tờ giấy màu bạc, bề mặt có hoa văn cổ quái, nặng và dày hơn quyển sách màu vàng. Khi Hàn Lập dùng liệt hỏa đỏ hồng nung, bề mặt tan chảy để lộ ra quang mang màu vàng — một quyển sách màu vàng ẩn bên trong không sợ lửa đốt.","nguon":["@c0240"]},{"id":"quyen-sach-mau-vang-ngung-nguyen","name":"Quyển sách màu vàng (Ngưng Nguyên công)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quyển sách màu vàng Hàn Lập chọn làm chủ công pháp, kích cỡ giống hệt sách bạc nhưng mỏng hơn, ghi Ngưng Nguyên công và Tụ Linh thuật.","detail":"Quyển sách màu vàng đựng trong hộp ngọc mà Hàn Lập chọn làm chủ công pháp ở Tàng thư thất. Hình dáng kích cỡ giống hệt quyển sách màu bạc hắn đang giữ, chỉ mỏng hơn và bề mặt phủ cổ văn dày đặc, ghi lại pháp quyết bình thường Ngưng Nguyên công cùng thần thông phụ trợ Tụ Linh thuật. Sự giống nhau về hình dáng khiến Hàn Lập nảy nghi hoặc.","nguon":["@c0240"]},{"id":"quyen-sach-mau-vang-an-trong-sach-bac","name":"Quyển sách màu vàng ẩn trong sách bạc","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quyển sách vàng lộ ra sau khi nung chảy bề mặt sách bạc, dạy phi kiếm và kiếm quang, không sợ lửa và nuốt trọn kiếm quang xanh của Hàn Lập.","detail":"Quyển sách màu vàng lộ ra sau khi Hàn Lập nung chảy bề mặt quyển sách màu bạc. Nội dung dạy điều khiển phi kiếm và Kiếm tu chi thuật tu luyện kiếm quang. Sách không sợ lửa đốt, không biến hóa; khi Hàn Lập quăng lên không và đánh một đạo kiếm quang xanh to như cái bát để tiêu hủy thì kiếm quang biến mất vô ảnh vô tung như bị sách nuốt, khiến hắn từ kinh hãi chuyển sang phấn chấn.","nguon":["@c0240"]}]};
